-- AssetHub 数据库完整表结构
-- 自动生成，用于 Docker 初始化

CREATE DATABASE IF NOT EXISTS zcgl CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE zcgl;

SET FOREIGN_KEY_CHECKS=0;
SET SESSION sql_mode='ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION';

CREATE TABLE IF NOT EXISTS `acceptance_application_assets` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `application_id` int NOT NULL COMMENT '验收申请ID',
  `asset_name` varchar(200) NOT NULL COMMENT '资产名称',
  `asset_code` varchar(100) DEFAULT NULL COMMENT '资产编号',
  `asset_brand` varchar(100) DEFAULT NULL COMMENT '品牌',
  `asset_model` varchar(100) DEFAULT NULL COMMENT '型号',
  `asset_specification` text COMMENT '规格',
  `purchase_date` date DEFAULT NULL COMMENT '采购日期',
  `purchase_amount` decimal(15,2) DEFAULT NULL COMMENT '采购金额',
  `order_index` int DEFAULT '0' COMMENT '排序索引',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_application_id` (`application_id`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `acceptance_application_assets_ibfk_1` FOREIGN KEY (`application_id`) REFERENCES `acceptance_applications` (`id`) ON DELETE CASCADE,
  CONSTRAINT `acceptance_application_assets_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='验收申请资产关联表';

CREATE TABLE IF NOT EXISTS `acceptance_application_files` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `application_id` int NOT NULL COMMENT '申请ID',
  `file_type` enum('安装图片','正常运行图片','安装报告单','采购合同','发票','其他资料') NOT NULL COMMENT '文件类型',
  `file_name` varchar(255) NOT NULL COMMENT '文件名',
  `file_path` varchar(500) NOT NULL COMMENT '文件路径',
  `file_size` bigint DEFAULT NULL COMMENT '文件大小（字节）',
  `mime_type` varchar(100) DEFAULT NULL COMMENT 'MIME类型',
  `uploaded_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_application` (`application_id`),
  KEY `idx_file_type` (`file_type`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `acceptance_application_files_ibfk_1` FOREIGN KEY (`application_id`) REFERENCES `acceptance_applications` (`id`) ON DELETE CASCADE,
  CONSTRAINT `acceptance_application_files_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='验收申请文件表';

CREATE TABLE IF NOT EXISTS `acceptance_application_shares` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `share_token` varchar(100) NOT NULL COMMENT '分享令牌',
  `share_url` varchar(500) DEFAULT NULL COMMENT '分享URL',
  `expires_at` datetime DEFAULT NULL COMMENT '过期时间',
  `max_applications` int DEFAULT '10' COMMENT '最大申请次数',
  `current_applications` int DEFAULT '0' COMMENT '当前申请次数',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否激活',
  `remark` text COMMENT '备注（如：供应商名称、联系方式等）',
  `supplier_name` varchar(200) DEFAULT NULL COMMENT '供应商/厂家名称',
  `supplier_contact` varchar(200) DEFAULT NULL COMMENT '供应商联系方式',
  PRIMARY KEY (`id`),
  UNIQUE KEY `share_token` (`share_token`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_share_token` (`share_token`),
  KEY `idx_expires_at` (`expires_at`),
  KEY `idx_is_active` (`is_active`),
  CONSTRAINT `acceptance_application_shares_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='验收申请分享链接表';

CREATE TABLE IF NOT EXISTS `acceptance_application_signatures` (
  `id` int NOT NULL AUTO_INCREMENT,
  `application_id` int NOT NULL COMMENT '申请ID',
  `signature_type` enum('使用科室签字','职能部门签字','企业签字') NOT NULL COMMENT '签字类型',
  `signer_name` varchar(50) NOT NULL COMMENT '签字人姓名',
  `signer_department` varchar(100) DEFAULT NULL COMMENT '签字人部门',
  `signer_company` varchar(200) DEFAULT NULL COMMENT '签字人所属企业',
  `signature_file_path` varchar(500) DEFAULT NULL COMMENT '签字图片路径',
  `signed_at` datetime DEFAULT NULL COMMENT '签字时间',
  `remark` text COMMENT '备注',
  `tenant_id` int NOT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_application` (`application_id`),
  KEY `idx_signature_type` (`signature_type`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `acceptance_application_signatures_ibfk_1` FOREIGN KEY (`application_id`) REFERENCES `acceptance_applications` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_acceptance_application_signatures_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='验收申请签字表';

CREATE TABLE IF NOT EXISTS `acceptance_applications` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `application_no` varchar(50) DEFAULT NULL COMMENT '申请编号',
  `company_name` varchar(200) NOT NULL COMMENT '企业名称',
  `company_contact` varchar(100) DEFAULT NULL COMMENT '企业联系人',
  `company_phone` varchar(50) DEFAULT NULL COMMENT '企业联系电话',
  `company_address` text COMMENT '企业地址',
  `company_email` varchar(100) DEFAULT NULL COMMENT '企业邮箱',
  `purchase_department` varchar(100) DEFAULT NULL COMMENT '采购部门',
  `use_department` varchar(100) DEFAULT NULL COMMENT '使用部门',
  `asset_name` varchar(200) NOT NULL COMMENT '资产名称',
  `asset_code` varchar(100) DEFAULT NULL COMMENT '资产编号',
  `asset_brand` varchar(100) DEFAULT NULL COMMENT '品牌',
  `asset_model` varchar(100) DEFAULT NULL COMMENT '型号',
  `asset_specification` text COMMENT '规格',
  `purchase_date` date DEFAULT NULL COMMENT '采购日期',
  `purchase_amount` decimal(15,2) DEFAULT NULL COMMENT '采购金额',
  `status` enum('待审核','审核中','已通过','已拒绝','已验收') DEFAULT '待审核' COMMENT '申请状态',
  `reviewer` varchar(50) DEFAULT NULL COMMENT '审核人',
  `review_date` datetime DEFAULT NULL COMMENT '审核日期',
  `review_comment` text COMMENT '审核意见',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `application_no` (`application_no`),
  KEY `idx_status` (`status`),
  KEY `idx_company` (`company_name`(191)),
  KEY `idx_application_no` (`application_no`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `acceptance_applications_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='验收申请表';

CREATE TABLE IF NOT EXISTS `adverse_events` (
  `id` int NOT NULL AUTO_INCREMENT,
  `event_code` varchar(50) NOT NULL COMMENT '事件编号',
  `asset_id` int DEFAULT NULL COMMENT '关联资产ID',
  `event_type` varchar(100) NOT NULL COMMENT '事件类型',
  `severity_level` enum('minor','moderate','serious','critical') NOT NULL COMMENT '严重程度',
  `occurrence_date` datetime NOT NULL COMMENT '发生时间',
  `discovery_date` datetime DEFAULT NULL COMMENT '发现时间',
  `reporter_id` int NOT NULL COMMENT '报告人ID',
  `description` text NOT NULL COMMENT '事件描述',
  `immediate_action` text COMMENT '立即采取措施',
  `status` enum('reported','investigating','processing','closed') DEFAULT 'reported' COMMENT '状态',
  `root_cause` text COMMENT '根本原因',
  `corrective_action` text COMMENT '纠正措施',
  `preventive_action` text COMMENT '预防措施',
  `closed_date` date DEFAULT NULL COMMENT '关闭日期',
  `closed_by` int DEFAULT NULL COMMENT '关闭人ID',
  `tenant_id` int DEFAULT '1' COMMENT '租户ID',
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_event_code` (`event_code`),
  KEY `idx_asset_id` (`asset_id`),
  KEY `idx_severity` (`severity_level`),
  KEY `idx_status` (`status`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='不良事件表';

CREATE TABLE IF NOT EXISTS `adverse_reaction_attachments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `record_id` int NOT NULL COMMENT '记录ID',
  `file_name` varchar(255) NOT NULL COMMENT '文件名',
  `file_path` varchar(500) NOT NULL COMMENT '文件路径',
  `file_size` int DEFAULT NULL COMMENT '文件大小（字节）',
  `file_type` varchar(50) DEFAULT NULL COMMENT '文件类型',
  `upload_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_record_id` (`record_id`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `adverse_reaction_attachments_ibfk_1` FOREIGN KEY (`record_id`) REFERENCES `adverse_reaction_records` (`id`) ON DELETE CASCADE,
  CONSTRAINT `adverse_reaction_attachments_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_adverse_reaction_attachments_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='不良反应附件表';

CREATE TABLE IF NOT EXISTS `adverse_reaction_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `report_no` varchar(100) NOT NULL COMMENT '报告编号',
  `asset_id` int DEFAULT NULL COMMENT '资产ID',
  `asset_code` varchar(100) DEFAULT NULL COMMENT '资产编号',
  `asset_name` varchar(200) DEFAULT NULL COMMENT '资产名称',
  `report_type` enum('设备故障','安全事故','质量事故','使用异常','其他') NOT NULL COMMENT '报告类型',
  `event_category` varchar(100) DEFAULT NULL COMMENT '事件分类',
  `severity` enum('轻微','一般','严重','重大') DEFAULT '一般' COMMENT '严重程度',
  `event_consequence` enum('无伤害','轻微伤害','中度伤害','重度伤害','死亡','设备损坏','其他') DEFAULT NULL COMMENT '事件后果',
  `event_level` enum('I级','II级','III级','IV级') DEFAULT NULL COMMENT '事件等级',
  `occurrence_date` datetime NOT NULL COMMENT '发生时间',
  `discovery_date` datetime DEFAULT NULL COMMENT '发现时间',
  `location` varchar(200) DEFAULT NULL COMMENT '发生地点',
  `department` varchar(100) DEFAULT NULL COMMENT '发生科室',
  `involved_persons` text COMMENT '涉及人员（JSON格式）',
  `reporter` varchar(50) NOT NULL COMMENT '上报人',
  `report_source` enum('系统上报','电话上报','邮件上报','现场上报','其他') DEFAULT '系统上报' COMMENT '上报来源',
  `reporter_phone` varchar(50) DEFAULT NULL COMMENT '上报人电话',
  `description` text NOT NULL COMMENT '事件描述',
  `cause_analysis` text COMMENT '原因分析',
  `cause_category` enum('设备故障','操作失误','管理缺陷','环境因素','其他') DEFAULT NULL COMMENT '原因分类',
  `impact_assessment` text COMMENT '影响评估',
  `handling_measures` text COMMENT '处理措施',
  `prevention_measures` text COMMENT '预防措施',
  `improvement_suggestions` text COMMENT '改进建议',
  `status` enum('待处理','处理中','已处理','已关闭','已归档') DEFAULT '待处理' COMMENT '处理状态',
  `handle_deadline` int DEFAULT NULL COMMENT '处理时限（小时）',
  `is_overdue` tinyint(1) DEFAULT '0' COMMENT '是否超时',
  `handler` varchar(50) DEFAULT NULL COMMENT '处理人',
  `handle_date` datetime DEFAULT NULL COMMENT '处理时间',
  `handle_result` text COMMENT '处理结果',
  `reviewer` varchar(50) DEFAULT NULL COMMENT '审核人',
  `review_date` datetime DEFAULT NULL COMMENT '审核时间',
  `review_comment` text COMMENT '审核意见',
  `close_reason` text COMMENT '关闭原因',
  `is_serious` tinyint(1) DEFAULT '0' COMMENT '是否严重事件',
  `reported_to_authority` tinyint(1) DEFAULT '0' COMMENT '是否已上报监管部门',
  `authority_report_date` datetime DEFAULT NULL COMMENT '上报监管部门时间',
  `related_assets` text COMMENT '相关资产（JSON格式，支持多个）',
  `remark` text COMMENT '备注',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已删除(0:否,1:是)',
  `deleted_at` datetime DEFAULT NULL COMMENT '删除时间',
  `deleted_by` varchar(64) DEFAULT NULL COMMENT '删除人ID',
  PRIMARY KEY (`id`),
  UNIQUE KEY `report_no` (`report_no`),
  KEY `idx_report_no` (`report_no`),
  KEY `idx_asset_id` (`asset_id`),
  KEY `idx_report_type` (`report_type`),
  KEY `idx_severity` (`severity`),
  KEY `idx_status` (`status`),
  KEY `idx_occurrence_date` (`occurrence_date`),
  KEY `idx_reporter` (`reporter`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_event_level` (`event_level`),
  KEY `idx_adverse_reaction_is_deleted` (`is_deleted`),
  KEY `idx_adverse_reaction_records_tenant_id` (`tenant_id`),
  CONSTRAINT `adverse_reaction_records_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='不良反应记录表';

CREATE TABLE IF NOT EXISTS `adverse_reaction_workflow` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `record_id` int NOT NULL COMMENT '记录ID',
  `step_name` varchar(100) NOT NULL COMMENT '步骤名称',
  `step_type` enum('上报','处理','审核','关闭','归档') NOT NULL COMMENT '步骤类型',
  `operator` varchar(50) NOT NULL COMMENT '操作人',
  `operation_time` datetime NOT NULL COMMENT '操作时间',
  `operation_result` enum('通过','退回','拒绝','完成') DEFAULT NULL COMMENT '操作结果',
  `comment` text COMMENT '操作意见',
  `next_handler` varchar(50) DEFAULT NULL COMMENT '下一步处理人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_record_id` (`record_id`),
  KEY `idx_operation_time` (`operation_time`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_adverse_reaction_workflow_tenant_id` (`tenant_id`),
  CONSTRAINT `adverse_reaction_workflow_ibfk_1` FOREIGN KEY (`record_id`) REFERENCES `adverse_reaction_records` (`id`) ON DELETE CASCADE,
  CONSTRAINT `adverse_reaction_workflow_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='不良事件处理流程记录表';

CREATE TABLE IF NOT EXISTS `ai_chat_messages` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `session_id` int NOT NULL COMMENT '会话ID',
  `role` enum('user','assistant') NOT NULL COMMENT '角色：user-用户，assistant-AI助手',
  `content` text NOT NULL COMMENT '消息内容',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_session_id` (`session_id`),
  KEY `idx_created_at` (`created_at`),
  CONSTRAINT `ai_chat_messages_ibfk_1` FOREIGN KEY (`session_id`) REFERENCES `ai_chat_sessions` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=167 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='AI对话消息表';

CREATE TABLE IF NOT EXISTS `ai_chat_sessions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `user_id` int NOT NULL COMMENT '用户ID',
  `session_name` varchar(200) DEFAULT NULL COMMENT '会话名称',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=39 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='AI对话会话表';

CREATE TABLE IF NOT EXISTS `ai_document_conversations` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `user_id` int NOT NULL COMMENT '用户ID',
  `conversation_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '对话ID',
  `message_role` enum('user','assistant','system') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '消息角色',
  `message_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '消息内容',
  `document_ids` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '关联文档ID列表(JSON数组)',
  `sources` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '来源文档信息(JSON)',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_tenant_user` (`tenant_id`,`user_id`),
  KEY `idx_conversation_id` (`conversation_id`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='AI文档对话历史表';

CREATE TABLE IF NOT EXISTS `ai_model` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `api_key` varchar(255) DEFAULT NULL,
  `api_domain` varchar(255) NOT NULL,
  `protocol` int NOT NULL,
  `supplier` int NOT NULL,
  `name` varchar(255) NOT NULL,
  `model_type` int NOT NULL,
  `base_model` varchar(255) NOT NULL,
  `default_model` tinyint(1) NOT NULL,
  `config` text NOT NULL,
  `status` int NOT NULL,
  `create_time` bigint NOT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_ai_model_id` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `alembic_version` (
  `version_num` varchar(32) NOT NULL,
  PRIMARY KEY (`version_num`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `alert_read_states` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `user_id` int NOT NULL,
  `alert_id` varchar(100) NOT NULL,
  `alert_type` varchar(64) NOT NULL,
  `related_id` int DEFAULT NULL,
  `read_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `handled_at` timestamp NULL DEFAULT NULL,
  `handled_by` int DEFAULT NULL,
  `handler_notes` text,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_alert_read_states_tenant_user_alert` (`tenant_id`,`user_id`,`alert_id`),
  KEY `idx_alert_read_states_tenant_user` (`tenant_id`,`user_id`),
  KEY `idx_alert_read_states_tenant_type` (`tenant_id`,`alert_type`),
  KEY `idx_alert_read_states_read_at` (`read_at`),
  KEY `idx_alert_read_states_handled_at` (`handled_at`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `assessment_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL COMMENT '用户ID',
  `assessment_name` varchar(200) NOT NULL COMMENT '考核名称',
  `assessment_type` varchar(100) DEFAULT NULL COMMENT '考核类型',
  `assessment_date` date NOT NULL COMMENT '考核日期',
  `score` decimal(5,2) DEFAULT NULL COMMENT '得分',
  `result` enum('pass','fail','excellent') DEFAULT NULL COMMENT '结果',
  `evaluator_id` int DEFAULT NULL COMMENT '考核人ID',
  `comments` text COMMENT '评语',
  `tenant_id` int DEFAULT '1' COMMENT '租户ID',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_assessment_date` (`assessment_date`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='考核记录表';

CREATE TABLE IF NOT EXISTS `asset_acceptance_checklist` (
  `id` int NOT NULL AUTO_INCREMENT,
  `acceptance_id` int NOT NULL COMMENT '验收记录ID',
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `category` varchar(100) NOT NULL COMMENT '检查类别：外观检查、功能测试、配件核对、资料核对、安装验收、安全验收',
  `item_name` varchar(200) NOT NULL COMMENT '检查项目名称',
  `item_description` text COMMENT '检查项目描述',
  `is_passed` tinyint(1) DEFAULT NULL COMMENT '是否通过：1-通过, 0-不通过, NULL-未检查',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `checked_by` varchar(100) DEFAULT NULL COMMENT '检查人',
  `checked_at` timestamp NULL DEFAULT NULL COMMENT '检查时间',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_acceptance_id` (`acceptance_id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_category` (`category`),
  KEY `idx_is_passed` (`is_passed`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='验收检查清单表';

CREATE TABLE IF NOT EXISTS `asset_acceptance_files` (
  `id` int NOT NULL AUTO_INCREMENT,
  `acceptance_id` int NOT NULL COMMENT '验收记录ID',
  `file_type` enum('安装图片','正常运行图片','安装报告单','采购合同','发票') NOT NULL COMMENT '文件类型',
  `file_name` varchar(255) NOT NULL COMMENT '文件名',
  `file_path` varchar(500) NOT NULL COMMENT '文件路径',
  `file_size` bigint DEFAULT NULL COMMENT '文件大小（字节）',
  `mime_type` varchar(100) DEFAULT NULL COMMENT 'MIME类型',
  `uploaded_by` varchar(50) DEFAULT NULL COMMENT '上传人',
  `uploaded_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `tenant_id` int NOT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_acceptance` (`acceptance_id`),
  KEY `idx_file_type` (`file_type`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `asset_acceptance_files_ibfk_1` FOREIGN KEY (`acceptance_id`) REFERENCES `asset_acceptance_records` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_asset_acceptance_files_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产验收文件表';

CREATE TABLE IF NOT EXISTS `asset_acceptance_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `asset_code` varchar(100) NOT NULL COMMENT '资产编号',
  `asset_name` varchar(200) NOT NULL COMMENT '资产名称',
  `supplier` varchar(200) DEFAULT NULL COMMENT '销售企业/供应商',
  `acceptance_date` date DEFAULT NULL COMMENT '验收日期',
  `acceptance_person` varchar(50) DEFAULT NULL COMMENT '验收人',
  `department` varchar(100) DEFAULT NULL COMMENT '使用科室',
  `functional_department` varchar(100) DEFAULT NULL COMMENT '职能部门',
  `status` enum('待验收','验收中','已验收','验收不合格') DEFAULT '待验收' COMMENT '验收状态',
  `remark` text COMMENT '备注',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `tenant_id` int NOT NULL,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已删除(0:否,1:是)',
  `deleted_at` datetime DEFAULT NULL COMMENT '删除时间',
  `deleted_by` varchar(64) DEFAULT NULL COMMENT '删除人ID',
  PRIMARY KEY (`id`),
  KEY `idx_status` (`status`),
  KEY `idx_acceptance_date` (`acceptance_date`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_asset_acceptance_records_is_deleted` (`is_deleted`),
  CONSTRAINT `fk_asset_acceptance_records_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产验收记录表';

CREATE TABLE IF NOT EXISTS `asset_acceptance_templates` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `asset_category` varchar(200) DEFAULT NULL COMMENT '适用的资产类别',
  `template_name` varchar(200) NOT NULL COMMENT '模板名称',
  `category` varchar(100) NOT NULL COMMENT '检查类别',
  `item_name` varchar(200) NOT NULL COMMENT '检查项目名称',
  `item_description` text COMMENT '检查项目描述',
  `is_required` tinyint(1) DEFAULT '1' COMMENT '是否必检项',
  `sort_order` int DEFAULT '0' COMMENT '排序',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_category` (`category`),
  KEY `idx_asset_category` (`asset_category`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='验收检查项模板表';

CREATE TABLE IF NOT EXISTS `asset_ai_analysis_logs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `asset_id` int DEFAULT NULL COMMENT '资产ID（可选，自定义分析可能没有）',
  `dimension` varchar(50) DEFAULT NULL COMMENT '分析维度（overview/value/utilization/maintenance/lifecycle/risk/optimization/custom）',
  `prompt` text NOT NULL COMMENT '用户输入的提示词',
  `response` text COMMENT 'AI返回的响应（JSON格式）',
  `user_id` int NOT NULL COMMENT '执行分析的用户ID',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `sql_execution` text COMMENT 'SQL执行结果（JSON格式）',
  `result_analysis` text COMMENT 'AI对结果的分析',
  `ai_source` varchar(50) DEFAULT NULL COMMENT 'AI模型来源',
  `result_analysis_source` varchar(50) DEFAULT NULL COMMENT '结果分析AI模型来源',
  `sql` text COMMENT 'AI生成的SQL语句',
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  PRIMARY KEY (`id`),
  KEY `idx_asset` (`asset_id`),
  KEY `idx_user` (`user_id`),
  KEY `idx_dimension` (`dimension`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `asset_ai_analysis_logs_ibfk_1` FOREIGN KEY (`asset_id`) REFERENCES `assets` (`id`) ON DELETE SET NULL,
  CONSTRAINT `asset_ai_analysis_logs_ibfk_2` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=233 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产AI分析日志表';

CREATE TABLE IF NOT EXISTS `asset_categories` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `name` varchar(100) NOT NULL COMMENT '分类名称',
  `code` varchar(50) NOT NULL COMMENT '分类编码',
  `parent_id` int DEFAULT '0' COMMENT '父分类ID',
  `level` int NOT NULL DEFAULT '1',
  `description` text COMMENT '分类描述',
  `is_public` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `code` (`code`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_cat_id` (`id`),
  CONSTRAINT `asset_categories_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_asset_categories_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=43 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产分类表';

CREATE TABLE IF NOT EXISTS `asset_change_logs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `asset_code` varchar(255) NOT NULL,
  `field_name` varchar(100) NOT NULL,
  `old_value` text,
  `new_value` text,
  `changed_by` varchar(100) DEFAULT NULL,
  `changed_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `tenant_id` int NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `idx_asset_id` (`asset_code`(191)),
  KEY `idx_changed_at` (`changed_at`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_asset_change_logs_code_tenant_time` (`asset_code`,`tenant_id`,`changed_at`)
) ENGINE=InnoDB AUTO_INCREMENT=28 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `asset_device_mapping` (
  `id` int NOT NULL AUTO_INCREMENT,
  `asset_code` varchar(255) NOT NULL COMMENT '资产ID',
  `device_id` varchar(100) NOT NULL COMMENT '设备ID',
  `bind_date` datetime NOT NULL COMMENT '绑定日期',
  `unbind_date` datetime DEFAULT NULL COMMENT '解绑日期',
  `bind_person` varchar(50) DEFAULT NULL COMMENT '绑定操作人',
  `unbind_person` varchar(50) DEFAULT NULL COMMENT '解绑操作人',
  `bind_reason` text COMMENT '绑定原因',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否激活',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `tenant_id` int NOT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_asset` (`asset_code`(191)),
  KEY `idx_device` (`device_id`),
  KEY `idx_active` (`is_active`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `fk_asset_device_mapping_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产设备关联表';

CREATE TABLE IF NOT EXISTS `asset_health_snapshots` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `asset_code` varchar(100) NOT NULL,
  `health_index` decimal(10,2) NOT NULL DEFAULT '0.00',
  `health_grade` varchar(5) NOT NULL DEFAULT 'E',
  `status_component` decimal(10,2) NOT NULL DEFAULT '0.00',
  `cost_component` decimal(10,2) NOT NULL DEFAULT '0.00',
  `risk_inverse_component` decimal(10,2) NOT NULL DEFAULT '0.00',
  `strategic_component` decimal(10,2) NOT NULL DEFAULT '0.00',
  `portfolio_overall_index` decimal(10,2) NOT NULL DEFAULT '0.00',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_asset_health_snapshots_tenant_asset_time` (`tenant_id`,`asset_code`,`created_at`),
  KEY `idx_asset_health_snapshots_tenant_time` (`tenant_id`,`created_at`),
  KEY `idx_asset_health_snapshots_tenant_grade` (`tenant_id`,`health_grade`,`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=351 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `asset_images` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `asset_code` varchar(100) NOT NULL,
  `file_id` varchar(255) NOT NULL,
  `temp_file_url` varchar(255) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `description` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_asset_images_asset_id` (`asset_code`),
  KEY `idx_asset_images_tenant_id` (`tenant_id`),
  KEY `idx_asset_images_asset_created` (`asset_code`,`created_at`),
  KEY `idx_asset_images_tenant_asset` (`tenant_id`,`asset_code`),
  KEY `idx_asset_images_code_tenant` (`asset_code`,`tenant_id`,`id`),
  CONSTRAINT `asset_images_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_asset_images_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=19363 DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `asset_label_print_queue` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL,
  `template_id` int NOT NULL,
  `asset_code` varchar(50) DEFAULT NULL,
  `zpl_content` text NOT NULL,
  `print_status` enum('pending','printing','completed','failed') NOT NULL DEFAULT 'pending',
  `printer_name` varchar(100) DEFAULT NULL,
  `error_message` text,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `printed_at` timestamp NULL DEFAULT NULL,
  `created_by` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_template_id` (`template_id`),
  KEY `idx_print_status` (`print_status`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_asset_label_print_queue_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `asset_label_templates` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL,
  `name` varchar(100) NOT NULL,
  `description` text,
  `width` decimal(10,2) NOT NULL,
  `height` decimal(10,2) NOT NULL,
  `dpi` int NOT NULL DEFAULT '300',
  `elements` text NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  `created_by` varchar(50) DEFAULT NULL,
  `updated_by` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_asset_label_templates_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `asset_location_history` (
  `id` int NOT NULL AUTO_INCREMENT,
  `asset_code` varchar(255) NOT NULL COMMENT '资产ID',
  `device_id` varchar(100) DEFAULT NULL COMMENT '物联网设备ID',
  `device_type` enum('RFID','GPS','蓝牙','WiFi','UWB','其他') DEFAULT NULL COMMENT '设备类型',
  `latitude` decimal(10,7) DEFAULT NULL COMMENT '纬度',
  `longitude` decimal(10,7) DEFAULT NULL COMMENT '经度',
  `altitude` decimal(10,2) DEFAULT NULL COMMENT '海拔高度（米）',
  `floor_number` int DEFAULT NULL COMMENT '楼层号',
  `building_name` varchar(200) DEFAULT NULL COMMENT '建筑物名称',
  `room_number` varchar(100) DEFAULT NULL COMMENT '房间号',
  `area_name` varchar(200) DEFAULT NULL COMMENT '区域名称',
  `address` varchar(500) DEFAULT NULL COMMENT '详细地址',
  `location_accuracy` decimal(10,2) DEFAULT NULL COMMENT '定位精度（米）',
  `signal_strength` int DEFAULT NULL COMMENT '信号强度',
  `battery_level` int DEFAULT NULL COMMENT '设备电量（百分比）',
  `record_time` datetime NOT NULL COMMENT '记录时间',
  `update_source` enum('设备自动上报','手动更新','系统同步') DEFAULT '设备自动上报' COMMENT '更新来源',
  `change_type` enum('位置移动','设备上报','手动更新','系统同步') DEFAULT '设备上报' COMMENT '变更类型',
  `movement_distance` decimal(10,2) DEFAULT NULL COMMENT '移动距离（米，相对于上次位置）',
  `movement_speed` decimal(10,2) DEFAULT NULL COMMENT '移动速度（米/秒）',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `tenant_id` int NOT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_asset` (`asset_code`(191)),
  KEY `idx_device` (`device_id`),
  KEY `idx_record_time` (`record_time`),
  KEY `idx_location` (`latitude`,`longitude`),
  KEY `idx_building` (`building_name`(191),`floor_number`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_location_asset_timestamp` (`asset_code`(191),`record_time`),
  KEY `idx_location_tenant_asset_timestamp` (`tenant_id`,`asset_code`(191),`record_time`),
  KEY `idx_location_tenant_building_floor` (`tenant_id`,`building_name`(191),`floor_number`),
  KEY `idx_asset_location_history_code_tenant_time` (`asset_code`,`tenant_id`,`record_time`),
  CONSTRAINT `fk_asset_location_history_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产位置历史记录表';

CREATE TABLE IF NOT EXISTS `asset_locations` (
  `id` int NOT NULL AUTO_INCREMENT,
  `asset_code` varchar(255) NOT NULL COMMENT '资产ID',
  `device_id` varchar(100) DEFAULT NULL COMMENT '物联网设备ID（如RFID标签、GPS设备等）',
  `device_type` enum('RFID','GPS','蓝牙','WiFi','UWB','其他') DEFAULT NULL COMMENT '设备类型',
  `latitude` decimal(10,7) DEFAULT NULL COMMENT '纬度',
  `longitude` decimal(10,7) DEFAULT NULL COMMENT '经度',
  `altitude` decimal(10,2) DEFAULT NULL COMMENT '海拔高度（米）',
  `floor_number` int DEFAULT NULL COMMENT '楼层号',
  `building_name` varchar(200) DEFAULT NULL COMMENT '建筑物名称',
  `room_number` varchar(100) DEFAULT NULL COMMENT '房间号',
  `area_name` varchar(200) DEFAULT NULL COMMENT '区域名称',
  `address` varchar(500) DEFAULT NULL COMMENT '详细地址',
  `location_accuracy` decimal(10,2) DEFAULT NULL COMMENT '定位精度（米）',
  `signal_strength` int DEFAULT NULL COMMENT '信号强度',
  `battery_level` int DEFAULT NULL COMMENT '设备电量（百分比）',
  `last_update_time` datetime NOT NULL COMMENT '最后更新时间',
  `update_source` enum('设备自动上报','手动更新','系统同步') DEFAULT '设备自动上报' COMMENT '更新来源',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否激活（1=激活，0=停用）',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `tenant_id` int NOT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_asset` (`asset_code`(191)),
  KEY `idx_device` (`device_id`),
  KEY `idx_location` (`latitude`,`longitude`),
  KEY `idx_building` (`building_name`(191),`floor_number`),
  KEY `idx_last_update` (`last_update_time`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `fk_asset_locations_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产位置表';

CREATE TABLE IF NOT EXISTS `asset_scrapping_appraisals` (
  `id` int NOT NULL AUTO_INCREMENT,
  `scrapping_id` int NOT NULL COMMENT '报废记录ID',
  `appraiser` varchar(100) NOT NULL COMMENT '鉴定人',
  `appraiser_id` int DEFAULT NULL COMMENT '鉴定人ID',
  `appraisal_date` datetime NOT NULL COMMENT '鉴定日期',
  `technical_condition` varchar(100) DEFAULT NULL COMMENT '技术状况',
  `scrapping_necessity` varchar(100) DEFAULT NULL COMMENT '报废必要性',
  `estimated_value` decimal(10,2) DEFAULT NULL COMMENT '预估残值',
  `appraisal_result` text NOT NULL COMMENT '鉴定结果',
  `appraisal_attachments` text COMMENT '鉴定附件',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL COMMENT '更新时间',
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  PRIMARY KEY (`id`),
  KEY `idx_scrapping_id` (`scrapping_id`),
  KEY `idx_asset_scrapping_appraisals_tenant_id` (`tenant_id`),
  CONSTRAINT `asset_scrapping_appraisals_ibfk_1` FOREIGN KEY (`scrapping_id`) REFERENCES `asset_scrapping_records` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产报废鉴定表';

CREATE TABLE IF NOT EXISTS `asset_scrapping_approvals` (
  `id` int NOT NULL AUTO_INCREMENT,
  `scrapping_id` int NOT NULL COMMENT '报废记录ID',
  `approver` varchar(100) NOT NULL COMMENT '审批人',
  `approver_id` int DEFAULT NULL COMMENT '审批人ID',
  `approval_level` int NOT NULL DEFAULT '1' COMMENT '审批级别',
  `approval_status` varchar(50) NOT NULL DEFAULT 'pending' COMMENT '审批状态: pending, approved, rejected',
  `approval_comment` text COMMENT '审批意见',
  `approval_date` datetime DEFAULT NULL COMMENT '审批日期',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL COMMENT '更新时间',
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  PRIMARY KEY (`id`),
  KEY `idx_scrapping_id` (`scrapping_id`),
  KEY `idx_approval_status` (`approval_status`),
  KEY `idx_asset_scrapping_approvals_tenant_id` (`tenant_id`),
  CONSTRAINT `asset_scrapping_approvals_ibfk_1` FOREIGN KEY (`scrapping_id`) REFERENCES `asset_scrapping_records` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产报废审批表';

CREATE TABLE IF NOT EXISTS `asset_scrapping_disposals` (
  `id` int NOT NULL AUTO_INCREMENT,
  `scrapping_id` int NOT NULL COMMENT '报废记录ID',
  `disposer` varchar(100) NOT NULL COMMENT '处置人',
  `disposer_id` int DEFAULT NULL COMMENT '处置人ID',
  `disposal_date` datetime NOT NULL COMMENT '处置日期',
  `disposal_method` varchar(100) NOT NULL COMMENT '处置方式',
  `disposal_company` varchar(255) DEFAULT NULL COMMENT '处置公司',
  `actual_value` decimal(10,2) DEFAULT NULL COMMENT '实际残值',
  `disposal_result` text NOT NULL COMMENT '处置结果',
  `disposal_attachments` text COMMENT '处置附件',
  `disposal_certificate` varchar(255) DEFAULT NULL COMMENT '处置证明',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL COMMENT '更新时间',
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  PRIMARY KEY (`id`),
  KEY `idx_scrapping_id` (`scrapping_id`),
  KEY `idx_asset_scrapping_disposals_tenant_id` (`tenant_id`),
  CONSTRAINT `asset_scrapping_disposals_ibfk_1` FOREIGN KEY (`scrapping_id`) REFERENCES `asset_scrapping_records` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产报废处置表';

CREATE TABLE IF NOT EXISTS `asset_scrapping_files` (
  `id` int NOT NULL AUTO_INCREMENT,
  `scrapping_id` int NOT NULL COMMENT '报废记录ID',
  `file_type` varchar(50) NOT NULL COMMENT '文件类型: application, appraisal, approval, disposal',
  `file_name` varchar(255) NOT NULL COMMENT '文件名',
  `file_path` varchar(500) NOT NULL COMMENT '文件路径',
  `file_size` bigint DEFAULT NULL COMMENT '文件大小',
  `mime_type` varchar(100) DEFAULT NULL COMMENT '文件类型',
  `uploaded_by` varchar(100) NOT NULL COMMENT '上传人',
  `uploaded_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '上传时间',
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  PRIMARY KEY (`id`),
  KEY `idx_scrapping_id` (`scrapping_id`),
  KEY `idx_file_type` (`file_type`),
  KEY `idx_asset_scrapping_files_tenant_id` (`tenant_id`),
  CONSTRAINT `asset_scrapping_files_ibfk_1` FOREIGN KEY (`scrapping_id`) REFERENCES `asset_scrapping_records` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产报废文件表';

CREATE TABLE IF NOT EXISTS `asset_scrapping_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `asset_code` varchar(50) NOT NULL COMMENT '资产编码',
  `asset_name` varchar(255) NOT NULL COMMENT '资产名称',
  `asset_model` varchar(255) DEFAULT NULL COMMENT '资产型号',
  `department` varchar(100) DEFAULT NULL COMMENT '使用部门',
  `applicant` varchar(100) NOT NULL COMMENT '申请人',
  `applicant_id` int DEFAULT NULL COMMENT '申请人ID',
  `apply_date` datetime NOT NULL COMMENT '申请日期',
  `scrapping_reason` text NOT NULL COMMENT '报废原因',
  `estimated_value` decimal(10,2) DEFAULT NULL COMMENT '预估残值',
  `current_status` varchar(50) NOT NULL DEFAULT 'pending' COMMENT '当前状态: pending, appraising, approved, rejected, disposing, completed',
  `appraiser` varchar(100) DEFAULT NULL COMMENT '鉴定人',
  `appraiser_id` int DEFAULT NULL COMMENT '鉴定人ID',
  `appraisal_date` datetime DEFAULT NULL COMMENT '鉴定日期',
  `appraisal_result` text COMMENT '鉴定结果',
  `approver` varchar(100) DEFAULT NULL COMMENT '审批人',
  `approver_id` int DEFAULT NULL COMMENT '审批人ID',
  `approval_date` datetime DEFAULT NULL COMMENT '审批日期',
  `approval_comment` text COMMENT '审批意见',
  `disposer` varchar(100) DEFAULT NULL COMMENT '处置人',
  `disposer_id` int DEFAULT NULL COMMENT '处置人ID',
  `disposal_date` datetime DEFAULT NULL COMMENT '处置日期',
  `disposal_method` varchar(100) DEFAULT NULL COMMENT '处置方式',
  `disposal_result` text COMMENT '处置结果',
  `actual_value` decimal(10,2) DEFAULT NULL COMMENT '实际残值',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT NULL,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已删除(0:否,1:是)',
  `deleted_at` datetime DEFAULT NULL COMMENT '删除时间',
  `deleted_by` varchar(64) DEFAULT NULL COMMENT '删除人ID',
  PRIMARY KEY (`id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_status` (`current_status`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_apply_date` (`apply_date`),
  KEY `idx_asset_scrapping_records_is_deleted` (`is_deleted`)
) ENGINE=InnoDB AUTO_INCREMENT=63 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产报废记录表';

CREATE TABLE IF NOT EXISTS `asset_shares` (
  `id` int NOT NULL AUTO_INCREMENT,
  `asset_id` int NOT NULL COMMENT '资产ID',
  `share_token` varchar(100) NOT NULL COMMENT '分享令牌',
  `share_url` varchar(500) DEFAULT NULL COMMENT '分享URL',
  `expires_at` datetime DEFAULT NULL COMMENT '过期时间',
  `max_uploads` int DEFAULT '5' COMMENT '最大上传次数（用于外部上传技术资料）',
  `current_uploads` int DEFAULT '0' COMMENT '当前上传次数',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否激活',
  `remark` text COMMENT '备注（如：厂家工程师姓名、联系方式等）',
  `supplier_name` varchar(200) DEFAULT NULL COMMENT '供应商/厂家名称',
  `supplier_contact` varchar(200) DEFAULT NULL COMMENT '供应商联系方式',
  `tenant_id` int NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `share_token` (`share_token`),
  KEY `idx_asset` (`asset_id`),
  KEY `idx_share_token` (`share_token`),
  KEY `idx_expires_at` (`expires_at`),
  KEY `idx_is_active` (`is_active`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `asset_shares_ibfk_1` FOREIGN KEY (`asset_id`) REFERENCES `assets` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_asset_shares_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产分享链接表';

CREATE TABLE IF NOT EXISTS `asset_transfer_requests` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `asset_code` varchar(50) NOT NULL,
  `asset_name` varchar(200) NOT NULL,
  `current_department` varchar(100) NOT NULL,
  `target_department` varchar(100) NOT NULL,
  `reason` text NOT NULL,
  `applicant` varchar(100) NOT NULL,
  `status` enum('pending','approved','rejected') DEFAULT 'pending',
  `approved_by` varchar(100) DEFAULT NULL,
  `approved_at` datetime DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_status` (`status`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_transfer_tenant` (`tenant_id`),
  KEY `idx_transfer_status` (`status`),
  CONSTRAINT `asset_transfer_requests_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_asset_transfer_requests_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=28 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `asset_transfers` (
  `id` int NOT NULL AUTO_INCREMENT,
  `transfer_no` varchar(100) NOT NULL COMMENT '调配单号',
  `asset_code` varchar(255) NOT NULL COMMENT '资产ID',
  `from_department` varchar(100) NOT NULL COMMENT '调出部门',
  `to_department` varchar(100) NOT NULL COMMENT '调入部门',
  `from_location` varchar(200) DEFAULT NULL COMMENT '调出位置',
  `to_location` varchar(200) DEFAULT NULL COMMENT '调入位置',
  `from_person` varchar(50) DEFAULT NULL COMMENT '调出责任人',
  `to_person` varchar(50) DEFAULT NULL COMMENT '调入责任人',
  `transfer_date` date NOT NULL COMMENT '调配日期',
  `transfer_reason` text COMMENT '调配原因',
  `status` enum('待审批','已批准','已完成','已取消') DEFAULT '待审批' COMMENT '调配状态',
  `approver` varchar(50) DEFAULT NULL COMMENT '审批人',
  `approve_date` date DEFAULT NULL COMMENT '审批日期',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `tenant_id` varchar(255) DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `idx_asset` (`asset_code`(191)),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产调配表';

CREATE TABLE IF NOT EXISTS `asset_usage_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `asset_code` varchar(100) NOT NULL,
  `asset_name` varchar(200) DEFAULT NULL,
  `usage_date` date NOT NULL,
  `usage_value` decimal(15,2) NOT NULL,
  `usage_type` varchar(50) NOT NULL,
  `cumulative_value` decimal(15,2) NOT NULL,
  `operator` varchar(100) DEFAULT NULL,
  `remark` text,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_usage_date` (`usage_date`),
  KEY `idx_usage_type` (`usage_type`),
  KEY `idx_asset_usage_records_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产使用量记录表';

CREATE TABLE IF NOT EXISTS `asset_workflow_actions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `transition_id` int NOT NULL,
  `action_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `action_config` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `sort_order` int DEFAULT '0',
  `is_active` tinyint(1) DEFAULT '1',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `tenant_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_transition` (`transition_id`),
  KEY `idx_asset_workflow_actions_tenant_id` (`tenant_id`),
  CONSTRAINT `asset_workflow_actions_ibfk_1` FOREIGN KEY (`transition_id`) REFERENCES `asset_workflow_transitions` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='资产流程动作表';

CREATE TABLE IF NOT EXISTS `asset_workflow_logs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `asset_id` int NOT NULL,
  `workflow_id` int NOT NULL,
  `transition_id` int NOT NULL,
  `from_state` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `to_state` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `operator_id` int DEFAULT NULL,
  `operator_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `metadata` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `action_result` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_asset` (`asset_id`),
  KEY `idx_workflow` (`workflow_id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_asset_workflow_logs_tenant_id` (`tenant_id`),
  CONSTRAINT `asset_workflow_logs_ibfk_1` FOREIGN KEY (`workflow_id`) REFERENCES `asset_workflows` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='资产流程日志表';

CREATE TABLE IF NOT EXISTS `asset_workflow_states` (
  `id` int NOT NULL AUTO_INCREMENT,
  `workflow_id` int NOT NULL,
  `state_key` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `state_label` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `color` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `sort_order` int DEFAULT '0',
  `is_terminal` tinyint(1) DEFAULT '0',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `tenant_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_workflow_state` (`workflow_id`,`state_key`),
  KEY `idx_workflow` (`workflow_id`),
  KEY `idx_asset_workflow_states_tenant_id` (`tenant_id`),
  CONSTRAINT `asset_workflow_states_ibfk_1` FOREIGN KEY (`workflow_id`) REFERENCES `asset_workflows` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='资产流程状态表';

CREATE TABLE IF NOT EXISTS `asset_workflow_transitions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `workflow_id` int NOT NULL,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `from_state` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `to_state` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `require_reason` tinyint(1) DEFAULT '0',
  `is_active` tinyint(1) DEFAULT '1',
  `sort_order` int DEFAULT '0',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `tenant_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_workflow` (`workflow_id`),
  KEY `idx_from_state` (`workflow_id`,`from_state`),
  KEY `idx_asset_workflow_transitions_tenant_id` (`tenant_id`),
  CONSTRAINT `asset_workflow_transitions_ibfk_1` FOREIGN KEY (`workflow_id`) REFERENCES `asset_workflows` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='资产流程迁移表';

CREATE TABLE IF NOT EXISTS `asset_workflows` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `status` enum('active','inactive') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'active',
  `is_default` tinyint(1) DEFAULT '0',
  `created_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_tenant_workflow` (`tenant_id`,`name`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_default` (`tenant_id`,`is_default`),
  KEY `idx_asset_workflows_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='资产流程定义表';

CREATE TABLE IF NOT EXISTS `assets` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL,
  `asset_code` varchar(100) DEFAULT NULL COMMENT '原始编码Acode',
  `code` varchar(100) DEFAULT NULL COMMENT '原始编码code',
  `code2` varchar(100) DEFAULT NULL COMMENT '原始编码code2',
  `code3` varchar(100) DEFAULT NULL COMMENT '原始编码code3',
  `asset_name` varchar(200) NOT NULL COMMENT '资产名称',
  `category_id` int NOT NULL COMMENT '分类ID',
  `category_secondary_id` int DEFAULT NULL COMMENT '二级分类ID',
  `brand` varchar(100) DEFAULT NULL COMMENT '品牌',
  `model` varchar(100) DEFAULT NULL COMMENT '型号',
  `property_certificate` varchar(100) DEFAULT NULL COMMENT '产权证号',
  `property_address` varchar(500) DEFAULT NULL COMMENT '坐落地址',
  `land_area` decimal(15,2) DEFAULT NULL COMMENT '土地面积（平方米）',
  `building_area` decimal(15,2) DEFAULT NULL COMMENT '建筑面积（平方米）',
  `land_use_right` varchar(100) DEFAULT NULL COMMENT '土地使用权类型',
  `building_structure` varchar(100) DEFAULT NULL COMMENT '建筑结构（如：框架结构、砖混结构等）',
  `license_plate` varchar(50) DEFAULT NULL COMMENT '车牌号码',
  `vehicle_type` varchar(50) DEFAULT NULL COMMENT '车辆类型（如：轿车、SUV、货车等）',
  `engine_number` varchar(100) DEFAULT NULL COMMENT '发动机号',
  `vin_number` varchar(100) DEFAULT NULL COMMENT '车架号（VIN码）',
  `serial_number` varchar(100) DEFAULT NULL,
  `specification` text COMMENT '规格参数',
  `purchase_date` date DEFAULT NULL COMMENT '购置日期',
  `purchase_price` decimal(15,2) DEFAULT NULL COMMENT '购置价格',
  `current_value` decimal(15,2) DEFAULT NULL COMMENT '当前价值',
  `accumulated_depreciation` decimal(15,2) DEFAULT NULL COMMENT '累计折旧',
  `depreciation_method` varchar(50) DEFAULT NULL COMMENT '折旧方式',
  `depreciation_years` int DEFAULT NULL COMMENT '折旧年限',
  `depreciation_months` int DEFAULT NULL COMMENT '已提折旧月份',
  `location` varchar(200) DEFAULT NULL COMMENT '存放位置',
  `storage_location` varchar(200) DEFAULT NULL,
  `department` varchar(100) DEFAULT NULL COMMENT '使用部门',
  `department_new` varchar(100) DEFAULT NULL,
  `use_department` varchar(100) DEFAULT NULL,
  `unit` varchar(200) DEFAULT NULL COMMENT '单位',
  `responsible_person` varchar(50) DEFAULT NULL COMMENT '责任人',
  `status` enum('在用','闲置','维修','报废','调配中') DEFAULT '在用' COMMENT '资产状态',
  `supplier` varchar(200) DEFAULT NULL COMMENT '供应商',
  `data_id` varchar(100) DEFAULT NULL COMMENT '数据标识',
  `original_created_at` datetime DEFAULT NULL COMMENT '原始创建时间',
  `warranty_period` int DEFAULT NULL COMMENT '保修期（月）',
  `warranty_end_date` date DEFAULT NULL COMMENT '保修到期日',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `updated_by` varchar(50) DEFAULT NULL COMMENT '更新人',
  `asset_department_code` varchar(50) DEFAULT NULL COMMENT '部门代码',
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已删除(0:否,1:是)',
  `deleted_at` datetime DEFAULT NULL COMMENT '删除时间',
  `deleted_by` varchar(64) DEFAULT NULL COMMENT '删除人ID',
  `asset_type` varchar(50) DEFAULT NULL COMMENT '资产类型',
  PRIMARY KEY (`id`),
  KEY `idx_category` (`category_id`),
  KEY `idx_code` (`asset_code`),
  KEY `idx_code2` (`code2`),
  KEY `idx_code3` (`code3`),
  KEY `idx_assets_tenant_id` (`tenant_id`),
  KEY `idx_assets_status` (`status`),
  KEY `idx_assets_department` (`department`),
  KEY `idx_assets_department_new` (`department_new`),
  KEY `idx_assets_purchase_date` (`purchase_date`),
  KEY `idx_secondary_category` (`category_secondary_id`),
  KEY `idx_assets_tenant_asset_code` (`tenant_id`,`asset_code`),
  KEY `idx_assets_tenant_status` (`tenant_id`,`status`),
  KEY `idx_assets_tenant_created_at` (`tenant_id`,`created_at`),
  KEY `idx_assets_tenant_purchase_date` (`tenant_id`,`purchase_date`),
  KEY `idx_assets_tenant_created` (`tenant_id`,`created_at`),
  KEY `idx_assets_tenant_dept` (`tenant_id`,`department_new`),
  KEY `idx_assets_category` (`category_id`),
  KEY `idx_assets_category_secondary` (`category_secondary_id`),
  KEY `idx_assets_asset_code` (`asset_code`),
  KEY `idx_assets_asset_name` (`asset_name`(191)),
  KEY `idx_assets_created_at` (`created_at`),
  KEY `idx_assets_is_deleted` (`is_deleted`),
  KEY `idx_assets_tenant_department` (`tenant_id`,`department_new`,`is_deleted`),
  KEY `idx_assets_tenant_category` (`tenant_id`,`category_id`,`is_deleted`),
  KEY `idx_assets_tenant_code` (`tenant_id`,`asset_code`),
  KEY `idx_assets_tenant_name` (`tenant_id`,`asset_name`(100)),
  CONSTRAINT `assets_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_assets_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=28493 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产主表';

CREATE TABLE IF NOT EXISTS `audit_logs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL,
  `user_id` int DEFAULT NULL COMMENT '用户ID',
  `username` varchar(50) DEFAULT NULL COMMENT '用户名',
  `real_name` varchar(50) DEFAULT NULL COMMENT '真实姓名',
  `role` varchar(50) DEFAULT NULL COMMENT '用户角色',
  `action_type` varchar(50) NOT NULL COMMENT '操作类型（create, update, delete, login, logout, view, export, import等）',
  `module` varchar(50) NOT NULL COMMENT '操作模块（assets, users, technical-documents, maintenance等）',
  `resource_type` varchar(50) DEFAULT NULL COMMENT '资源类型（asset, user, document等）',
  `resource_id` int DEFAULT NULL COMMENT '资源ID',
  `resource_name` varchar(200) DEFAULT NULL COMMENT '资源名称（如资产名称、用户名等）',
  `action_description` text COMMENT '操作描述',
  `old_value` text COMMENT '修改前的值（JSON格式）',
  `new_value` text COMMENT '修改后的值（JSON格式）',
  `ip_address` varchar(50) DEFAULT NULL COMMENT 'IP地址',
  `user_agent` text COMMENT '用户代理（浏览器信息）',
  `request_method` varchar(10) DEFAULT NULL COMMENT 'HTTP方法（GET, POST, PUT, DELETE）',
  `request_path` varchar(500) DEFAULT NULL COMMENT '请求路径',
  `request_params` text COMMENT '请求参数（JSON格式）',
  `response_status` int DEFAULT NULL COMMENT '响应状态码',
  `error_message` text COMMENT '错误信息（如果操作失败）',
  `execution_time` int DEFAULT NULL COMMENT '执行时间（毫秒）',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_username` (`username`),
  KEY `idx_action_type` (`action_type`),
  KEY `idx_module` (`module`),
  KEY `idx_resource_type` (`resource_type`),
  KEY `idx_resource_id` (`resource_id`),
  KEY `idx_audit_logs_tenant` (`tenant_id`),
  KEY `idx_audit_logs_user` (`user_id`),
  KEY `idx_audit_logs_created` (`created_at`),
  KEY `idx_audit_logs_time_user` (`tenant_id`,`created_at`,`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=7068 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='操作日志表（审计）';

CREATE TABLE IF NOT EXISTS `chat` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `create_time` datetime DEFAULT NULL,
  `create_by` bigint DEFAULT NULL,
  `brief` varchar(64) DEFAULT NULL,
  `chat_type` varchar(20) NOT NULL,
  `datasource` bigint DEFAULT NULL,
  `engine_type` varchar(64) NOT NULL,
  `oid` bigint DEFAULT NULL,
  `origin` int DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `chat_record` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `chat_id` bigint NOT NULL,
  `create_time` datetime DEFAULT NULL,
  `finish_time` datetime DEFAULT NULL,
  `create_by` bigint DEFAULT NULL,
  `datasource` bigint DEFAULT NULL,
  `engine_type` varchar(64) DEFAULT NULL,
  `question` text,
  `sql_answer` text,
  `sql` text,
  `sql_exec_result` text,
  `data` text,
  `chart_answer` text,
  `chart` text,
  `full_sql_message` text,
  `full_chart_message` text,
  `finish` tinyint(1) DEFAULT NULL,
  `error` text,
  `analysis` text,
  `predict` text,
  `full_analysis_message` text,
  `full_predict_message` text,
  `predict_data` text,
  `ai_modal_id` bigint DEFAULT NULL,
  `first_chat` tinyint(1) DEFAULT NULL,
  `recommended_question_answer` text,
  `recommended_question` text,
  `datasource_select_answer` text,
  `token_sql` varchar(256) DEFAULT NULL,
  `token_chart` varchar(256) DEFAULT NULL,
  `token_analysis` varchar(256) DEFAULT NULL,
  `token_predict` varchar(256) DEFAULT NULL,
  `full_recommended_question_message` text,
  `token_recommended_question` varchar(256) DEFAULT NULL,
  `full_select_datasource_message` text,
  `token_select_datasource_question` varchar(256) DEFAULT NULL,
  `analysis_record_id` bigint DEFAULT NULL,
  `predict_record_id` bigint DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `cloud_sync_events` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `source_id` int NOT NULL,
  `event_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `event_payload` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'received',
  `processed_at` datetime DEFAULT NULL,
  `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_source` (`source_id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_status` (`status`),
  KEY `idx_cloud_sync_events_tenant_id` (`tenant_id`),
  CONSTRAINT `cloud_sync_events_ibfk_1` FOREIGN KEY (`source_id`) REFERENCES `cloud_sync_sources` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='云/IoT同步事件';

CREATE TABLE IF NOT EXISTS `cloud_sync_sources` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `source_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'active',
  `secret_token` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `config_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_status` (`status`),
  KEY `idx_cloud_sync_sources_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='云/IoT同步源';

CREATE TABLE IF NOT EXISTS `common_asset_stats` (
  `id` int NOT NULL AUTO_INCREMENT,
  `asset_name` varchar(100) NOT NULL COMMENT '资产名称',
  `count` int DEFAULT '0' COMMENT '数量',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '更新时间',
  `tenant_id` int NOT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `fk_common_asset_stats_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=50339 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='通用资产统计表（按科室）';

CREATE TABLE IF NOT EXISTS `core_dashboard` (
  `id` varchar(50) NOT NULL,
  `name` varchar(255) DEFAULT NULL,
  `pid` varchar(50) DEFAULT NULL,
  `workspace_id` varchar(50) DEFAULT NULL,
  `org_id` varchar(50) DEFAULT NULL,
  `level` int DEFAULT NULL,
  `node_type` varchar(255) DEFAULT NULL,
  `type` varchar(50) DEFAULT NULL,
  `canvas_style_data` text,
  `component_data` text,
  `mobile_layout` smallint DEFAULT NULL,
  `status` int DEFAULT NULL,
  `self_watermark_status` int DEFAULT NULL,
  `sort` int DEFAULT NULL,
  `create_time` bigint DEFAULT NULL,
  `create_by` varchar(255) DEFAULT NULL,
  `update_time` bigint DEFAULT NULL,
  `update_by` varchar(255) DEFAULT NULL,
  `remark` varchar(255) DEFAULT NULL,
  `source` varchar(255) DEFAULT NULL,
  `delete_flag` smallint DEFAULT NULL,
  `delete_time` bigint DEFAULT NULL,
  `delete_by` varchar(255) DEFAULT NULL,
  `version` int DEFAULT NULL,
  `content_id` varchar(50) DEFAULT NULL,
  `check_version` varchar(50) DEFAULT NULL,
  `canvas_view_info` text,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `core_datasource` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(128) NOT NULL,
  `description` varchar(512) DEFAULT NULL,
  `type` varchar(64) NOT NULL,
  `configuration` text,
  `create_time` datetime DEFAULT NULL,
  `create_by` bigint DEFAULT NULL,
  `status` varchar(64) DEFAULT NULL,
  `type_name` varchar(64) DEFAULT NULL,
  `num` varchar(256) DEFAULT NULL,
  `oid` bigint DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `core_field` (
  `id` int NOT NULL AUTO_INCREMENT,
  `ds_id` bigint DEFAULT NULL,
  `table_id` bigint DEFAULT NULL,
  `checked` tinyint(1) NOT NULL,
  `field_name` text,
  `field_type` varchar(128) DEFAULT NULL,
  `field_comment` text,
  `custom_comment` text,
  `field_index` bigint DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `core_table` (
  `id` int NOT NULL AUTO_INCREMENT,
  `ds_id` bigint DEFAULT NULL,
  `checked` tinyint(1) NOT NULL,
  `table_name` text,
  `table_comment` text,
  `custom_comment` text,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `dashboard_configs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `config_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_active` tinyint(1) DEFAULT '0',
  `created_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_active` (`tenant_id`,`is_active`),
  KEY `idx_dashboard_configs_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='仪表盘配置表';

CREATE TABLE IF NOT EXISTS `data_filter_rules` (
  `id` int NOT NULL AUTO_INCREMENT,
  `role` varchar(50) NOT NULL COMMENT '角色代码',
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `resource_type` varchar(50) NOT NULL COMMENT '资源类型',
  `filter_field` varchar(100) NOT NULL COMMENT '过滤字段',
  `filter_operator` varchar(20) NOT NULL COMMENT '过滤操作符: eq/in/like',
  `filter_value` text NOT NULL COMMENT '过滤值',
  `priority` int DEFAULT '0' COMMENT '优先级',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否启用',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_role_resource_field` (`role`,`tenant_id`,`resource_type`,`filter_field`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_resource_type` (`resource_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='数据过滤规则表';

CREATE TABLE IF NOT EXISTS `database_backups` (
  `id` int NOT NULL AUTO_INCREMENT,
  `file_name` varchar(255) NOT NULL COMMENT '备份文件名',
  `file_path` varchar(500) NOT NULL COMMENT '备份文件路径',
  `file_size` bigint NOT NULL COMMENT '文件大小（字节）',
  `description` text COMMENT '备份描述',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `restored_by` varchar(50) DEFAULT NULL COMMENT '恢复人',
  `restored_at` timestamp NULL DEFAULT NULL COMMENT '恢复时间',
  `tenant_id` int NOT NULL DEFAULT '1' COMMENT '租户ID',
  `tenant_name` varchar(100) DEFAULT NULL COMMENT '租户名称',
  PRIMARY KEY (`id`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=16 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='数据库备份记录表';

CREATE TABLE IF NOT EXISTS `department_maintenance_costs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `department` varchar(100) NOT NULL,
  `year` int NOT NULL,
  `month` int NOT NULL,
  `labor_cost` decimal(15,2) DEFAULT '0.00',
  `material_cost` decimal(15,2) DEFAULT '0.00',
  `external_cost` decimal(15,2) DEFAULT '0.00',
  `other_cost` decimal(15,2) DEFAULT '0.00',
  `total_cost` decimal(15,2) DEFAULT '0.00',
  `maintenance_count` int DEFAULT '0',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_department_year_month` (`tenant_id`,`department`,`year`,`month`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_department` (`department`),
  KEY `idx_year_month` (`year`,`month`),
  KEY `idx_department_maintenance_costs_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='部门维护成本表';

CREATE TABLE IF NOT EXISTS `departments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `department_code` varchar(50) NOT NULL,
  `department_name` varchar(100) NOT NULL,
  `parent_code` varchar(50) DEFAULT NULL,
  `level` int DEFAULT NULL,
  `status` varchar(20) DEFAULT 'active' COMMENT '部门状态：active-启用，inactive-停用',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_departments_tenant_id` (`tenant_id`),
  KEY `idx_dept_tenant_code` (`tenant_id`,`department_code`),
  KEY `idx_dept_tenant` (`tenant_id`),
  KEY `idx_dept_tenant_name` (`tenant_id`,`department_name`),
  KEY `idx_departments_department_name` (`department_name`),
  KEY `idx_departments_department_code` (`department_code`),
  CONSTRAINT `departments_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_departments_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=125 DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `ds_permission` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `enable` tinyint(1) NOT NULL,
  `auth_target_type` varchar(128) DEFAULT NULL,
  `auth_target_id` bigint DEFAULT NULL,
  `type` varchar(64) NOT NULL,
  `ds_id` bigint DEFAULT NULL,
  `table_id` bigint DEFAULT NULL,
  `expression_tree` text,
  `permissions` text,
  `white_list_user` text,
  `create_time` datetime DEFAULT NULL,
  `name` varchar(128) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `ds_rules` (
  `id` int NOT NULL AUTO_INCREMENT,
  `enable` tinyint(1) NOT NULL,
  `name` varchar(128) NOT NULL,
  `description` varchar(512) DEFAULT NULL,
  `permission_list` text,
  `user_list` text,
  `white_list_user` text,
  `create_time` datetime DEFAULT NULL,
  `oid` bigint DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `environment_monitoring` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `device_id` int NOT NULL COMMENT '设备ID',
  `location` varchar(200) DEFAULT NULL COMMENT '位置',
  `temperature` decimal(5,2) DEFAULT NULL COMMENT '温度(°C)',
  `humidity` decimal(5,2) DEFAULT NULL COMMENT '湿度(%)',
  `pressure` decimal(8,2) DEFAULT NULL COMMENT '气压(hPa)',
  `pm25` decimal(6,2) DEFAULT NULL COMMENT 'PM2.5',
  `co2` decimal(8,2) DEFAULT NULL COMMENT 'CO2浓度',
  `other_metrics` text COMMENT '其他指标(JSON格式)',
  `alert_status` enum('normal','warning','critical') DEFAULT 'normal' COMMENT '告警状态',
  `monitored_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '监测时间',
  `tenant_id` int DEFAULT '1' COMMENT '租户ID',
  PRIMARY KEY (`id`),
  KEY `idx_device_id` (`device_id`),
  KEY `idx_alert_status` (`alert_status`),
  KEY `idx_monitored_at` (`monitored_at`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='环境监测表';

CREATE TABLE IF NOT EXISTS `high_risk_action_idempotency` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL DEFAULT '0',
  `actor_key` varchar(128) NOT NULL,
  `idempotency_key` varchar(128) NOT NULL,
  `action_id` varchar(64) NOT NULL,
  `action_fingerprint` varchar(255) NOT NULL,
  `request_hash` char(64) NOT NULL,
  `status` varchar(20) NOT NULL DEFAULT 'processing',
  `response_status` int DEFAULT NULL,
  `response_body` mediumtext,
  `error_message` text,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  `expires_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_hra_idempotency` (`tenant_id`,`actor_key`,`idempotency_key`),
  KEY `idx_hra_expires_at` (`expires_at`),
  KEY `idx_hra_action_id` (`action_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1387 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `idle_assets` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `asset_code` varchar(100) DEFAULT NULL COMMENT '资产编号或临时标识',
  `asset_id` int DEFAULT NULL COMMENT '资产ID（现有资产时填写，临时资产可空）',
  `publish_date` date NOT NULL COMMENT '发布日期',
  `publish_person` varchar(50) NOT NULL COMMENT '发布人',
  `expected_use` varchar(200) DEFAULT NULL COMMENT '期望用途',
  `contact_person` varchar(50) DEFAULT NULL COMMENT '联系人',
  `contact_phone` varchar(20) DEFAULT NULL COMMENT '联系电话',
  `status` enum('发布中','已分配','已取消') DEFAULT '发布中' COMMENT '发布状态',
  `allocated_to` varchar(100) DEFAULT NULL COMMENT '分配对象',
  `allocated_date` date DEFAULT NULL COMMENT '分配日期',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_asset` (`asset_id`),
  KEY `idx_status` (`status`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_idle_tenant_status` (`tenant_id`,`status`),
  KEY `idx_idle_tenant_publish` (`tenant_id`,`publish_date`),
  KEY `idx_idle_asset_code` (`asset_code`),
  CONSTRAINT `idle_assets_ibfk_1` FOREIGN KEY (`asset_id`) REFERENCES `assets` (`id`) ON DELETE CASCADE,
  CONSTRAINT `idle_assets_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='闲置资产发布表';

CREATE TABLE IF NOT EXISTS `intelligent_alerts` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `alert_type` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '告警类型',
  `alert_title` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '告警标题',
  `alert_content` text COLLATE utf8mb4_unicode_ci COMMENT '告警内容',
  `urgency` enum('low','medium','high','critical') COLLATE utf8mb4_unicode_ci DEFAULT 'medium',
  `related_id` int DEFAULT NULL COMMENT '关联ID',
  `related_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '关联类型',
  `status` enum('pending','read','handled') COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `handled_at` timestamp NULL DEFAULT NULL,
  `handled_by` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_alert_type` (`alert_type`),
  KEY `idx_status` (`status`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `inventory` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `material_id` int NOT NULL,
  `current_stock` decimal(15,2) DEFAULT '0.00',
  `available_stock` decimal(15,2) DEFAULT '0.00',
  `reserved_stock` decimal(15,2) DEFAULT '0.00',
  `last_stock_date` date DEFAULT NULL,
  `last_restock_quantity` decimal(15,2) DEFAULT '0.00',
  `average_cost` decimal(10,2) DEFAULT '0.00',
  `total_value` decimal(15,2) DEFAULT '0.00',
  `location` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `storage_condition` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_material_id` (`material_id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_inventory_tenant_id` (`tenant_id`),
  CONSTRAINT `inventory_ibfk_1` FOREIGN KEY (`material_id`) REFERENCES `materials` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `inventory_details` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `inventory_id` int NOT NULL COMMENT '盘点单ID',
  `asset_code` varchar(255) NOT NULL COMMENT '资产ID',
  `expected_location` varchar(200) DEFAULT NULL COMMENT '预期位置',
  `actual_location` varchar(200) DEFAULT NULL COMMENT '实际位置',
  `expected_status` varchar(50) DEFAULT NULL COMMENT '预期状态',
  `actual_status` varchar(50) DEFAULT NULL COMMENT '实际状态',
  `discrepancy_type` enum('正常','位置不符','状态不符','缺失','多余') DEFAULT '正常' COMMENT '差异类型',
  `discrepancy_desc` text COMMENT '差异说明',
  `checked_by` varchar(50) DEFAULT NULL COMMENT '自助盘点人',
  `checked_by_name` varchar(100) DEFAULT NULL COMMENT '盘点人姓名',
  `checked_at` datetime DEFAULT NULL COMMENT '盘点时间',
  `check_method` varchar(20) DEFAULT NULL COMMENT '盘点方式',
  `scan_time` datetime DEFAULT NULL COMMENT '扫描时间',
  `scan_type` enum('qr_code','manual','barcode') DEFAULT NULL COMMENT '扫描类型',
  `scan_by` varchar(50) DEFAULT NULL COMMENT '扫描人',
  `photo_url` varchar(500) DEFAULT NULL COMMENT '照片URL',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已删除(0:否,1:是)',
  `deleted_at` datetime DEFAULT NULL COMMENT '删除时间',
  `deleted_by` varchar(64) DEFAULT NULL COMMENT '删除人ID',
  PRIMARY KEY (`id`),
  KEY `idx_inventory` (`inventory_id`),
  KEY `idx_asset` (`asset_code`(191)),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_inventory_details_inventory_id` (`inventory_id`),
  KEY `idx_inventory_details_discrepancy_type` (`discrepancy_type`),
  KEY `idx_inventory_details_checked_at` (`checked_at`),
  KEY `idx_inventory_details_asset_code` (`asset_code`(191)),
  KEY `idx_inventory_details_is_deleted` (`is_deleted`),
  CONSTRAINT `inventory_details_ibfk_1` FOREIGN KEY (`inventory_id`) REFERENCES `inventory_records` (`id`) ON DELETE CASCADE,
  CONSTRAINT `inventory_details_ibfk_3` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=29 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='盘点明细表';

CREATE TABLE IF NOT EXISTS `inventory_discrepancies` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL,
  `inventory_id` int NOT NULL,
  `detail_id` int NOT NULL,
  `asset_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `discrepancy_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `expected_location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `actual_location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `expected_status` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `actual_status` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `handling_status` enum('待处理','处理中','已处理','已忽略') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '待处理',
  `handling_method` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `handler` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `handler_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `handling_date` datetime DEFAULT NULL,
  `handling_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_inventory_discrepancies_tenant_id` (`tenant_id`),
  KEY `idx_inventory_discrepancies_inventory_id` (`inventory_id`),
  KEY `idx_inventory_discrepancies_detail_id` (`detail_id`),
  KEY `idx_inventory_discrepancies_asset_code` (`asset_code`(191)),
  KEY `idx_inventory_discrepancies_handling_status` (`handling_status`),
  CONSTRAINT `inventory_discrepancies_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE,
  CONSTRAINT `inventory_discrepancies_ibfk_2` FOREIGN KEY (`inventory_id`) REFERENCES `inventory_records` (`id`) ON DELETE CASCADE,
  CONSTRAINT `inventory_discrepancies_ibfk_3` FOREIGN KEY (`detail_id`) REFERENCES `inventory_details` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `inventory_plan_details` (
  `id` int NOT NULL AUTO_INCREMENT,
  `plan_id` int NOT NULL,
  `department_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `asset_category` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `estimated_count` int DEFAULT '0',
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  PRIMARY KEY (`id`),
  KEY `idx_inventory_plan_details_plan_id` (`plan_id`),
  KEY `idx_inventory_plan_details_tenant_id` (`tenant_id`),
  CONSTRAINT `inventory_plan_details_ibfk_1` FOREIGN KEY (`plan_id`) REFERENCES `inventory_plans` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `inventory_plans` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL,
  `plan_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `plan_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `start_date` date DEFAULT NULL,
  `end_date` date DEFAULT NULL,
  `status` enum('draft','active','completed','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'draft',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `plan_no` (`plan_no`),
  KEY `idx_inventory_plans_tenant_id` (`tenant_id`),
  KEY `idx_inventory_plans_plan_no` (`plan_no`),
  KEY `idx_inventory_plans_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='盘点计划表';

CREATE TABLE IF NOT EXISTS `inventory_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `inventory_no` varchar(100) NOT NULL COMMENT '盘点单号',
  `inventory_date` date NOT NULL COMMENT '盘点日期',
  `inventory_type` enum('全面盘点','抽查盘点','专项盘点') NOT NULL COMMENT '盘点类型',
  `inventory_person` varchar(50) NOT NULL COMMENT '盘点人',
  `status` enum('进行中','已完成','已取消') DEFAULT '进行中' COMMENT '盘点状态',
  `self_check_enabled` tinyint(1) DEFAULT '0' COMMENT '是否启用自助盘点',
  `self_check_start` datetime DEFAULT NULL COMMENT '自助盘点开始时间',
  `self_check_end` datetime DEFAULT NULL COMMENT '自助盘点结束时间',
  `self_check_scope` varchar(20) DEFAULT 'mine' COMMENT '自助盘点范围',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已删除(0:否,1:是)',
  `deleted_at` datetime DEFAULT NULL COMMENT '删除时间',
  `deleted_by` varchar(64) DEFAULT NULL COMMENT '删除人ID',
  PRIMARY KEY (`id`),
  UNIQUE KEY `inventory_no` (`inventory_no`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_inventory_tenant` (`tenant_id`),
  KEY `idx_inventory_status` (`status`),
  KEY `idx_inventory_records_tenant_id` (`tenant_id`),
  KEY `idx_inventory_records_status` (`status`),
  KEY `idx_inventory_records_inventory_no` (`inventory_no`),
  KEY `idx_inventory_records_created_at` (`created_at`),
  KEY `idx_inventory_records_self_check` (`self_check_enabled`,`self_check_start`,`self_check_end`),
  KEY `idx_inventory_records_is_deleted` (`is_deleted`),
  CONSTRAINT `inventory_records_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=32 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='盘点记录表';

CREATE TABLE IF NOT EXISTS `inventory_scan_logs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL DEFAULT '1' COMMENT '租户ID',
  `inventory_id` int NOT NULL COMMENT '盘点记录ID',
  `asset_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '资产编号',
  `scan_time` datetime NOT NULL COMMENT '扫描时间',
  `scan_type` enum('qr_code','manual','barcode') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'qr_code' COMMENT '扫描类型',
  `scan_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '扫描人',
  `location` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '扫描位置',
  `status` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '资产状态',
  `result` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '盘点结果',
  `photo_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '照片URL',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_inventory_id` (`inventory_id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_scan_time` (`scan_time`),
  KEY `idx_scan_by` (`scan_by`),
  KEY `idx_inventory_scan_logs_inventory_id` (`inventory_id`),
  KEY `idx_inventory_scan_logs_asset_code` (`asset_code`),
  KEY `idx_inventory_scan_logs_scan_time` (`scan_time`),
  KEY `idx_inventory_scan_logs_scan_by` (`scan_by`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='盘点扫描日志表';

CREATE TABLE IF NOT EXISTS `inventory_tasks` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL,
  `inventory_id` int NOT NULL,
  `task_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `assignee` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `assignee_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `department_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `estimated_count` int DEFAULT '0',
  `actual_count` int DEFAULT '0',
  `status` enum('待分配','已分配','进行中','已完成','已取消') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '待分配',
  `start_time` datetime DEFAULT NULL,
  `end_time` datetime DEFAULT NULL,
  `created_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_inventory_tasks_tenant_id` (`tenant_id`),
  KEY `idx_inventory_tasks_inventory_id` (`inventory_id`),
  KEY `idx_inventory_tasks_assignee` (`assignee`),
  KEY `idx_inventory_tasks_status` (`status`),
  KEY `idx_inventory_tasks_department` (`department_code`),
  CONSTRAINT `inventory_tasks_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE,
  CONSTRAINT `inventory_tasks_ibfk_2` FOREIGN KEY (`inventory_id`) REFERENCES `inventory_records` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `inventory_transactions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `transaction_date` datetime DEFAULT NULL,
  `transaction_type` enum('入库','出库','调拨','盘点','报废') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `material_id` int NOT NULL,
  `quantity` decimal(15,2) NOT NULL,
  `unit_price` decimal(10,2) DEFAULT '0.00',
  `total_amount` decimal(15,2) DEFAULT '0.00',
  `source_location` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `target_location` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reference_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reference_id` int DEFAULT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `operator` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_transaction_date` (`transaction_date`),
  KEY `idx_transaction_type` (`transaction_type`),
  KEY `idx_material_id` (`material_id`),
  KEY `idx_reference` (`reference_type`,`reference_id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_inventory_transactions_tenant_id` (`tenant_id`),
  CONSTRAINT `inventory_transactions_ibfk_1` FOREIGN KEY (`material_id`) REFERENCES `materials` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `iot_asset_monitor_ts` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `device_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '设备ID',
  `asset_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '资产编码',
  `runtime_state` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '运行状态',
  `signal_strength` int DEFAULT NULL COMMENT '信号强度',
  `battery_level` int DEFAULT NULL COMMENT '电量',
  `cpu_usage` decimal(10,2) DEFAULT NULL COMMENT 'CPU占用',
  `memory_usage` decimal(10,2) DEFAULT NULL COMMENT '内存占用',
  `error_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '错误码',
  `event_time` datetime NOT NULL COMMENT '事件时间',
  `ingest_source` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'http' COMMENT '接入来源',
  `payload_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '原始数据',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_asset_mon_tenant_device_time` (`tenant_id`,`device_id`,`event_time`),
  KEY `idx_asset_mon_asset_time` (`asset_code`,`event_time`),
  KEY `idx_asset_mon_event_time` (`event_time`)
) ENGINE=InnoDB AUTO_INCREMENT=1030 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='资产监测时序数据表';

CREATE TABLE IF NOT EXISTS `iot_data_points` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `device_id` int NOT NULL COMMENT '设备ID',
  `data_type` varchar(50) NOT NULL COMMENT '数据类型',
  `metric_name` varchar(100) NOT NULL COMMENT '指标名称',
  `metric_value` decimal(18,4) NOT NULL COMMENT '指标值',
  `unit` varchar(20) DEFAULT NULL COMMENT '单位',
  `collected_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '采集时间',
  `tenant_id` int DEFAULT '1' COMMENT '租户ID',
  PRIMARY KEY (`id`),
  KEY `idx_device_id` (`device_id`),
  KEY `idx_metric_name` (`metric_name`),
  KEY `idx_collected_at` (`collected_at`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='IoT数据点表';

CREATE TABLE IF NOT EXISTS `iot_device_connectors` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `device_db_id` int NOT NULL,
  `protocol` varchar(32) NOT NULL,
  `transport` varchar(32) DEFAULT NULL,
  `endpoint_url` varchar(500) DEFAULT NULL,
  `topic` varchar(255) DEFAULT NULL,
  `auth_type` varchar(32) DEFAULT NULL,
  `auth_username` varchar(128) DEFAULT NULL,
  `auth_secret` varchar(255) DEFAULT NULL,
  `payload_format` varchar(32) DEFAULT NULL,
  `qos_level` tinyint DEFAULT '0',
  `custom_config` longtext,
  `is_enabled` tinyint(1) DEFAULT '1',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_connector_device` (`tenant_id`,`device_db_id`),
  KEY `idx_tenant_device` (`tenant_id`,`device_db_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `iot_devices` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `device_id` varchar(100) NOT NULL COMMENT '设备唯一标识',
  `device_name` varchar(200) DEFAULT NULL COMMENT '设备名称',
  `device_type` enum('RFID','GPS','蓝牙','WiFi','UWB','其他') NOT NULL COMMENT '设备类型',
  `manufacturer` varchar(100) DEFAULT NULL COMMENT '制造商',
  `model` varchar(100) DEFAULT NULL COMMENT '型号',
  `serial_number` varchar(100) DEFAULT NULL COMMENT '序列号',
  `mac_address` varchar(50) DEFAULT NULL COMMENT 'MAC地址',
  `firmware_version` varchar(50) DEFAULT NULL COMMENT '固件版本',
  `install_date` date DEFAULT NULL COMMENT '安装日期',
  `install_location` varchar(200) DEFAULT NULL COMMENT '安装位置',
  `battery_type` varchar(50) DEFAULT NULL COMMENT '电池类型',
  `battery_capacity` int DEFAULT NULL COMMENT '电池容量（mAh）',
  `update_interval` int DEFAULT NULL COMMENT '上报间隔（秒）',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否激活',
  `last_online_time` datetime DEFAULT NULL COMMENT '最后在线时间',
  `status` enum('在线','离线','故障','维护中') DEFAULT '离线' COMMENT '设备状态',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `device_id` (`device_id`),
  KEY `idx_device_id` (`device_id`),
  KEY `idx_type` (`device_type`),
  KEY `idx_status` (`status`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_iot_tenant_status` (`tenant_id`,`status`),
  KEY `idx_iot_tenant_last_online` (`tenant_id`,`last_online_time`),
  KEY `idx_iot_tenant_type_active` (`tenant_id`,`device_type`,`is_active`),
  CONSTRAINT `fk_iot_devices_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `iot_devices_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=15 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='物联网设备表';

CREATE TABLE IF NOT EXISTS `iot_environment_monitor_ts` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `device_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '设备ID',
  `asset_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '资产编码',
  `temperature` decimal(10,2) DEFAULT NULL COMMENT '温度',
  `humidity` decimal(10,2) DEFAULT NULL COMMENT '湿度',
  `pressure` decimal(12,2) DEFAULT NULL COMMENT '气压',
  `co2` decimal(10,2) DEFAULT NULL COMMENT '二氧化碳浓度',
  `pm25` decimal(10,2) DEFAULT NULL COMMENT 'PM2.5',
  `voc` decimal(10,2) DEFAULT NULL COMMENT '挥发性有机物',
  `battery_level` int DEFAULT NULL COMMENT '电量',
  `event_time` datetime NOT NULL COMMENT '事件时间',
  `ingest_source` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'http' COMMENT '接入来源',
  `payload_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '原始数据',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_env_ts_tenant_device_time` (`tenant_id`,`device_id`,`event_time`),
  KEY `idx_env_ts_asset_time` (`asset_code`,`event_time`),
  KEY `idx_env_ts_event_time` (`event_time`)
) ENGINE=InnoDB AUTO_INCREMENT=48 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='环境监测时序数据表';

CREATE TABLE IF NOT EXISTS `iot_patient_volume_ts` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `asset_code` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `patient_id` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `event_time` datetime NOT NULL,
  `ingest_source` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'http',
  `payload_json` longtext COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_patient_volume_tenant_asset_time` (`tenant_id`,`asset_code`,`event_time`),
  KEY `idx_patient_volume_tenant_patient_time` (`tenant_id`,`patient_id`,`event_time`),
  KEY `idx_patient_volume_event_time` (`event_time`)
) ENGINE=InnoDB AUTO_INCREMENT=2290 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='患者量统计时序数据表';

CREATE TABLE IF NOT EXISTS `iot_tenant_tokens` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `token_name` varchar(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `token_hash` char(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `token_prefix` varchar(24) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `scope_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` enum('active','revoked') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active',
  `expires_at` datetime DEFAULT NULL,
  `last_used_at` datetime DEFAULT NULL,
  `created_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `revoked_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `revoked_at` datetime DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `rotated_from_id` bigint DEFAULT NULL,
  `rotated_to_id` bigint DEFAULT NULL,
  `grace_until` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_iot_tenant_token_hash` (`token_hash`),
  KEY `idx_iot_tenant_status` (`tenant_id`,`status`),
  KEY `idx_iot_tenant_created_at` (`tenant_id`,`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='企业IoT接口鉴权Token';

CREATE TABLE IF NOT EXISTS `iot_zone_location_ts` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `device_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '设备ID',
  `asset_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '资产编码',
  `location_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '区域编码',
  `area_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '区域名称',
  `building_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '建筑名称',
  `floor_number` int DEFAULT NULL COMMENT '楼层',
  `rssi` int DEFAULT NULL COMMENT '信号强度',
  `accuracy` decimal(10,2) DEFAULT NULL COMMENT '定位精度',
  `battery_level` int DEFAULT NULL COMMENT '电量',
  `event_time` datetime NOT NULL COMMENT '事件时间',
  `ingest_source` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'http' COMMENT '接入来源',
  `payload_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '原始数据',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_zone_ts_tenant_device_time` (`tenant_id`,`device_id`,`event_time`),
  KEY `idx_zone_ts_asset_time` (`asset_code`,`event_time`),
  KEY `idx_zone_ts_location_code_time` (`location_code`,`event_time`),
  KEY `idx_zone_ts_event_time` (`event_time`)
) ENGINE=InnoDB AUTO_INCREMENT=47 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='区域定位时序数据表';

CREATE TABLE IF NOT EXISTS `license` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `license_key` text NOT NULL,
  `f2c_license` text NOT NULL,
  `create_time` bigint NOT NULL,
  `update_time` bigint NOT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_license_id` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `location_alert_rules` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `asset_code` varchar(100) DEFAULT NULL COMMENT '资产编号',
  `asset_id` int DEFAULT NULL COMMENT '资产ID（NULL表示全局规则）',
  `rule_name` varchar(200) NOT NULL COMMENT '规则名称',
  `rule_type` enum('越界告警','静止告警','移动告警','离线告警','低电量告警') NOT NULL COMMENT '规则类型',
  `geofence_type` enum('圆形','多边形','建筑物') DEFAULT NULL COMMENT '地理围栏类型',
  `geofence_data` text COMMENT '地理围栏数据（JSON格式）',
  `alert_condition` text COMMENT '告警条件（JSON格式）',
  `alert_level` enum('低','中','高','紧急') DEFAULT '中' COMMENT '告警级别',
  `is_enabled` tinyint(1) DEFAULT '1' COMMENT '是否启用',
  `notify_users` text COMMENT '通知用户列表（JSON数组）',
  `notify_channels` text COMMENT '通知渠道（JSON数组：短信、邮件、系统消息等）',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_asset` (`asset_id`),
  KEY `idx_type` (`rule_type`),
  KEY `idx_enabled` (`is_enabled`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_location_alert_rules_tenant_id` (`tenant_id`),
  CONSTRAINT `location_alert_rules_ibfk_1` FOREIGN KEY (`asset_id`) REFERENCES `assets` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='位置告警规则表';

CREATE TABLE IF NOT EXISTS `location_alerts` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `asset_code` varchar(100) DEFAULT NULL COMMENT '资产编号',
  `asset_id` int NOT NULL COMMENT '资产ID',
  `rule_id` int DEFAULT NULL COMMENT '告警规则ID',
  `alert_type` enum('越界告警','静止告警','移动告警','离线告警','低电量告警') NOT NULL COMMENT '告警类型',
  `alert_level` enum('低','中','高','紧急') DEFAULT '中' COMMENT '告警级别',
  `alert_content` text COMMENT '告警内容',
  `current_location` text COMMENT '当前位置信息（JSON格式）',
  `trigger_time` datetime NOT NULL COMMENT '触发时间',
  `is_handled` tinyint(1) DEFAULT '0' COMMENT '是否已处理',
  `handle_time` datetime DEFAULT NULL COMMENT '处理时间',
  `handle_person` varchar(50) DEFAULT NULL COMMENT '处理人',
  `handle_result` text COMMENT '处理结果',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_asset` (`asset_id`),
  KEY `idx_rule` (`rule_id`),
  KEY `idx_type` (`alert_type`),
  KEY `idx_handled` (`is_handled`),
  KEY `idx_trigger_time` (`trigger_time`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_location_alerts_tenant_id` (`tenant_id`),
  CONSTRAINT `location_alerts_ibfk_1` FOREIGN KEY (`asset_id`) REFERENCES `assets` (`id`) ON DELETE CASCADE,
  CONSTRAINT `location_alerts_ibfk_2` FOREIGN KEY (`rule_id`) REFERENCES `location_alert_rules` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='位置告警记录表';

CREATE TABLE IF NOT EXISTS `location_codes` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `location_code` varchar(100) NOT NULL COMMENT '位置编号',
  `location_name` varchar(200) NOT NULL COMMENT '位置名称',
  `description` text COMMENT '位置描述',
  `building_name` varchar(200) DEFAULT NULL COMMENT '建筑物名称',
  `floor_number` int DEFAULT NULL COMMENT '楼层号',
  `room_number` varchar(100) DEFAULT NULL COMMENT '房间号',
  `area_name` varchar(200) DEFAULT NULL COMMENT '区域名称',
  `latitude` decimal(10,7) DEFAULT NULL COMMENT '纬度',
  `longitude` decimal(10,7) DEFAULT NULL COMMENT '经度',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否激活',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `location_code` (`location_code`),
  KEY `idx_location_code` (`location_code`),
  KEY `idx_location_name` (`location_name`(191)),
  KEY `idx_building` (`building_name`(191),`floor_number`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `fk_location_codes_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `location_codes_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='位置编码表';

CREATE TABLE IF NOT EXISTS `maintenance_cost_summary` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `asset_code` varchar(100) NOT NULL,
  `asset_name` varchar(200) DEFAULT NULL,
  `year` int NOT NULL,
  `month` int NOT NULL,
  `labor_cost` decimal(15,2) DEFAULT '0.00',
  `material_cost` decimal(15,2) DEFAULT '0.00',
  `external_cost` decimal(15,2) DEFAULT '0.00',
  `other_cost` decimal(15,2) DEFAULT '0.00',
  `total_cost` decimal(15,2) DEFAULT '0.00',
  `maintenance_count` int DEFAULT '0',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_asset_year_month` (`tenant_id`,`asset_code`,`year`,`month`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_year_month` (`year`,`month`),
  KEY `idx_maintenance_cost_summary_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='维护成本汇总表';

CREATE TABLE IF NOT EXISTS `maintenance_costs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `maintenance_log_id` int DEFAULT NULL,
  `work_order_id` int DEFAULT NULL,
  `asset_code` varchar(100) NOT NULL,
  `asset_name` varchar(200) DEFAULT NULL,
  `cost_date` date NOT NULL,
  `cost_type` enum('labor','material','external','other') NOT NULL,
  `amount` decimal(15,2) NOT NULL,
  `description` text,
  `department` varchar(100) DEFAULT NULL,
  `location` varchar(200) DEFAULT NULL,
  `created_by` varchar(100) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_maintenance_log_id` (`maintenance_log_id`),
  KEY `idx_work_order_id` (`work_order_id`),
  KEY `idx_cost_date` (`cost_date`),
  KEY `idx_cost_type` (`cost_type`),
  CONSTRAINT `maintenance_costs_ibfk_1` FOREIGN KEY (`maintenance_log_id`) REFERENCES `maintenance_logs` (`id`) ON DELETE SET NULL,
  CONSTRAINT `maintenance_costs_ibfk_2` FOREIGN KEY (`work_order_id`) REFERENCES `work_orders` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='维护成本记录表';

CREATE TABLE IF NOT EXISTS `maintenance_evaluations` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `maintenance_log_id` int NOT NULL,
  `asset_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `maintenance_date` date NOT NULL,
  `maintenance_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `effectiveness_score` int DEFAULT NULL,
  `problem_resolved` tinyint(1) DEFAULT '1',
  `downtime_hours` decimal(10,2) DEFAULT '0.00',
  `production_impact` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `technician_skill_score` int DEFAULT NULL,
  `response_time_score` int DEFAULT NULL,
  `quality_score` int DEFAULT NULL,
  `overall_score` int DEFAULT NULL,
  `evaluation_date` datetime DEFAULT NULL,
  `evaluator` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `evaluation_remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_maintenance_log` (`maintenance_log_id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_tenant` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `maintenance_level_plans` (
  `id` int NOT NULL AUTO_INCREMENT,
  `plan_code` varchar(50) NOT NULL COMMENT '计划编码',
  `asset_id` int NOT NULL COMMENT '资产ID',
  `maintenance_level` enum('daily','level1','level2','level3') NOT NULL,
  `plan_date` date NOT NULL COMMENT '计划日期',
  `actual_date` date DEFAULT NULL COMMENT '实际执行日期',
  `executor_id` int DEFAULT NULL COMMENT '执行人ID',
  `maintenance_result` enum('pass','fail','partial') DEFAULT NULL COMMENT '保养结果',
  `status` enum('planned','processing','completed','overdue') DEFAULT 'planned',
  `tenant_id` int DEFAULT '1',
  `created_by` int DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_asset_id` (`asset_id`),
  KEY `idx_status` (`status`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='分级保养计划表';

CREATE TABLE IF NOT EXISTS `maintenance_level_templates` (
  `id` int NOT NULL AUTO_INCREMENT,
  `template_code` varchar(50) NOT NULL COMMENT '模板编码',
  `template_name` varchar(200) NOT NULL COMMENT '模板名称',
  `maintenance_level` enum('daily','level1','level2','level3') NOT NULL COMMENT '保养级别',
  `asset_category` varchar(100) DEFAULT NULL COMMENT '适用资产类别',
  `cycle_days` int DEFAULT '30' COMMENT '保养周期(天)',
  `maintenance_items` text COMMENT '保养项目',
  `status` enum('active','inactive') DEFAULT 'active',
  `tenant_id` int DEFAULT '1',
  `created_by` int DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_maintenance_level` (`maintenance_level`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='分级保养模板表';

CREATE TABLE IF NOT EXISTS `maintenance_log_attachments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `maintenance_log_id` int NOT NULL COMMENT '维护日志ID',
  `file_name` varchar(255) NOT NULL COMMENT '文件名',
  `file_path` varchar(500) NOT NULL COMMENT '文件路径',
  `file_type` varchar(50) DEFAULT NULL COMMENT '文件类型',
  `file_size` int DEFAULT NULL COMMENT '文件大小（字节）',
  `upload_date` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '上传日期',
  `uploaded_by` varchar(50) DEFAULT NULL COMMENT '上传人',
  `description` text COMMENT '文件描述',
  `tenant_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_maintenance_log` (`maintenance_log_id`),
  KEY `idx_maintenance_log_attachments_tenant_id` (`tenant_id`),
  CONSTRAINT `maintenance_log_attachments_ibfk_1` FOREIGN KEY (`maintenance_log_id`) REFERENCES `maintenance_logs` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='维护日志附件表';

CREATE TABLE IF NOT EXISTS `maintenance_logs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `asset_code` varchar(100) NOT NULL COMMENT '资产编号',
  `asset_name` varchar(200) NOT NULL COMMENT '资产名称',
  `maintenance_type` enum('日常维护','预防性维护','故障维修','定期保养','其他') NOT NULL COMMENT '维护类型',
  `maintenance_method` varchar(100) DEFAULT NULL COMMENT '维护方式（现场/送修/远程）',
  `maintenance_date` date NOT NULL COMMENT '维护日期',
  `maintenance_person` varchar(50) NOT NULL COMMENT '维护人员',
  `maintenance_location` varchar(200) DEFAULT NULL COMMENT '维护地点',
  `maintenance_content` text COMMENT '维护内容',
  `maintenance_cost` decimal(15,2) DEFAULT '0.00' COMMENT '维护费用',
  `supplier_name` varchar(200) DEFAULT NULL COMMENT '供应商名称',
  `maintenance_duration` int DEFAULT NULL COMMENT '维护耗时（分钟）',
  `parts_replaced` text COMMENT '更换部件',
  `warranty_info` text COMMENT '保修信息',
  `next_maintenance_date` date DEFAULT NULL COMMENT '下次维护日期',
  `status` enum('已完成','进行中','已取消') DEFAULT '已完成' COMMENT '维护状态',
  `quality_check` enum('合格','不合格','待检查') DEFAULT '待检查' COMMENT '质量检查结果',
  `quality_check_person` varchar(50) DEFAULT NULL COMMENT '质量检查人',
  `quality_check_date` date DEFAULT NULL COMMENT '质量检查日期',
  `remark` text COMMENT '备注',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  `labor_cost` decimal(15,2) DEFAULT '0.00',
  `material_cost` decimal(15,2) DEFAULT '0.00',
  `external_cost` decimal(15,2) DEFAULT '0.00',
  `total_cost` decimal(15,2) DEFAULT '0.00',
  PRIMARY KEY (`id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_maintenance_date` (`maintenance_date`),
  KEY `idx_maintenance_type` (`maintenance_type`),
  KEY `idx_status` (`status`),
  KEY `idx_maintenance_person` (`maintenance_person`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_asset_maintenance_date` (`maintenance_date`),
  KEY `idx_maintenance_type_date` (`maintenance_type`,`maintenance_date`),
  KEY `idx_maintenance_tenant_asset_status` (`tenant_id`,`asset_code`,`status`),
  KEY `idx_maintenance_tenant_date` (`tenant_id`,`maintenance_date`),
  KEY `idx_maintenance_logs_tenant_code` (`tenant_id`,`asset_code`),
  KEY `idx_maintenance_logs_tenant_date` (`tenant_id`,`maintenance_date`),
  KEY `idx_maintenance_logs_type_status` (`tenant_id`,`maintenance_type`,`status`),
  CONSTRAINT `fk_maintenance_logs_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `maintenance_logs_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=54 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='维护日志记录表';

CREATE TABLE IF NOT EXISTS `maintenance_material_requirements` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `maintenance_id` int NOT NULL,
  `maintenance_type` enum('maintenance_log','work_order','preventive_plan') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `material_id` int NOT NULL,
  `required_quantity` decimal(15,2) NOT NULL,
  `issued_quantity` decimal(15,2) DEFAULT '0.00',
  `unit_price` decimal(10,2) DEFAULT '0.00',
  `total_cost` decimal(15,2) DEFAULT '0.00',
  `status` enum('待发料','部分发料','已发料','取消') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '待发料',
  `issued_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `issued_date` datetime DEFAULT NULL,
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_maintenance` (`maintenance_type`,`maintenance_id`),
  KEY `idx_material_id` (`material_id`),
  KEY `idx_status` (`status`),
  KEY `idx_tenant` (`tenant_id`),
  CONSTRAINT `maintenance_material_requirements_ibfk_1` FOREIGN KEY (`material_id`) REFERENCES `materials` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `maintenance_plan_history` (
  `id` int NOT NULL AUTO_INCREMENT,
  `plan_id` int NOT NULL COMMENT '维护计划ID',
  `maintenance_date` date NOT NULL COMMENT '维护日期',
  `maintenance_person` varchar(50) DEFAULT NULL COMMENT '维护人',
  `actual_hours` decimal(10,2) DEFAULT NULL COMMENT '实际工时',
  `maintenance_result` enum('正常','异常','需维修') DEFAULT '正常' COMMENT '维护结果',
  `maintenance_notes` text COMMENT '维护备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_plan_id` (`plan_id`),
  KEY `idx_maintenance_date` (`maintenance_date`),
  CONSTRAINT `maintenance_plan_history_ibfk_1` FOREIGN KEY (`plan_id`) REFERENCES `preventive_maintenance_plans` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='维护计划历史记录表';

CREATE TABLE IF NOT EXISTS `maintenance_plans` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT '1',
  `plan_name` varchar(200) NOT NULL COMMENT '计划名称',
  `asset_id` int DEFAULT NULL COMMENT '资产ID',
  `asset_code` varchar(100) DEFAULT NULL COMMENT '资产编号',
  `asset_name` varchar(200) DEFAULT NULL COMMENT '资产名称',
  `maintenance_type` varchar(50) NOT NULL COMMENT '维护类型',
  `cycle_type` varchar(20) NOT NULL COMMENT '周期类型',
  `cycle_value` int NOT NULL COMMENT '周期值',
  `next_maintenance_date` date DEFAULT NULL COMMENT '下次维护日期',
  `maintenance_content` text COMMENT '维护内容',
  `responsible_person` varchar(50) DEFAULT NULL COMMENT '负责人',
  `status` varchar(20) DEFAULT 'active' COMMENT '计划状态',
  `last_maintenance_date` date DEFAULT NULL COMMENT '上次维护日期',
  `remark` text COMMENT '备注',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_asset` (`asset_id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_next_maintenance_date` (`next_maintenance_date`),
  KEY `idx_status` (`status`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='预防性维护计划表';

CREATE TABLE IF NOT EXISTS `maintenance_reminder_configs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `plan_id` int NOT NULL,
  `reminder_days` int NOT NULL DEFAULT '7' COMMENT '提前提醒天数',
  `reminder_types` varchar(500) DEFAULT NULL COMMENT '提醒方式数组(JSON格式)',
  `recipient` varchar(500) DEFAULT NULL COMMENT '提醒接收人',
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_plan_tenant` (`plan_id`,`tenant_id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_plan_id` (`plan_id`),
  KEY `idx_maintenance_reminder_configs_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='维护计划提醒配置表';

CREATE TABLE IF NOT EXISTS `maintenance_reminder_history` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `plan_id` int NOT NULL,
  `reminder_type` varchar(50) NOT NULL COMMENT '提醒类型：system/email/sms',
  `recipient` varchar(200) NOT NULL,
  `reminder_date` date NOT NULL,
  `status` enum('已发送','发送失败','已读') DEFAULT '已发送',
  `message` text,
  `sent_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_plan_id` (`plan_id`),
  KEY `idx_reminder_date` (`reminder_date`),
  KEY `idx_maintenance_reminder_history_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='维护提醒历史记录表';

CREATE TABLE IF NOT EXISTS `maintenance_reminders` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `plan_id` int NOT NULL,
  `asset_code` varchar(100) NOT NULL,
  `asset_name` varchar(200) DEFAULT NULL,
  `plan_name` varchar(200) NOT NULL,
  `next_maintenance_date` date NOT NULL,
  `reminder_date` date NOT NULL,
  `status` enum('未处理','已处理','已忽略') DEFAULT '未处理',
  `responsible_person` varchar(100) DEFAULT NULL,
  `department` varchar(100) DEFAULT NULL,
  `location` varchar(200) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_plan_id` (`plan_id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_reminder_date` (`reminder_date`),
  KEY `idx_status` (`status`),
  KEY `idx_maintenance_reminders_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='维护计划提醒表';

CREATE TABLE IF NOT EXISTS `maintenance_requests` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `request_no` varchar(100) NOT NULL COMMENT '申请单号',
  `asset_code` varchar(100) NOT NULL COMMENT '资产编号',
  `asset_name` varchar(200) NOT NULL COMMENT '资产名称',
  `fault_description` text NOT NULL COMMENT '故障描述',
  `fault_level` enum('一般','紧急','严重') DEFAULT '一般' COMMENT '故障级别',
  `request_date` date NOT NULL COMMENT '申请日期',
  `request_person` varchar(50) NOT NULL COMMENT '申请人',
  `request_department` varchar(100) DEFAULT NULL COMMENT '申请部门',
  `contact_phone` varchar(20) DEFAULT NULL COMMENT '联系电话',
  `expected_repair_date` date DEFAULT NULL COMMENT '期望维修日期',
  `status` enum('待审批','已批准','维修中','已完成','已拒绝','已取消') DEFAULT '待审批' COMMENT '申请状态',
  `approver` varchar(50) DEFAULT NULL COMMENT '审批人',
  `approve_date` date DEFAULT NULL COMMENT '审批日期',
  `approve_comment` text COMMENT '审批意见',
  `repair_person` varchar(50) DEFAULT NULL COMMENT '维修人员',
  `repair_start_date` date DEFAULT NULL COMMENT '维修开始日期',
  `repair_end_date` date DEFAULT NULL COMMENT '维修结束日期',
  `repair_cost` decimal(15,2) DEFAULT '0.00' COMMENT '维修费用',
  `repair_content` text COMMENT '维修内容',
  `parts_replaced` text COMMENT '更换部件',
  `remark` text COMMENT '备注',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `request_no` (`request_no`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_request_no` (`request_no`),
  KEY `idx_request_date` (`request_date`),
  KEY `idx_status` (`status`),
  KEY `idx_fault_level` (`fault_level`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `maintenance_requests_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=77 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='故障维修申请表';

CREATE TABLE IF NOT EXISTS `maintenance_templates` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `template_name` varchar(200) NOT NULL COMMENT '模板名称',
  `asset_type` varchar(50) DEFAULT NULL COMMENT '资产类型',
  `brand` varchar(100) DEFAULT NULL COMMENT '品牌',
  `model` varchar(100) DEFAULT NULL COMMENT '型号',
  `maintenance_items` text COMMENT '维护项目清单（JSON格式）',
  `cycle_type` enum('按天','按周','按月','按季度','按年') DEFAULT NULL COMMENT '周期类型',
  `cycle_value` int DEFAULT NULL COMMENT '周期值',
  `estimated_hours` decimal(10,2) DEFAULT NULL COMMENT '预计工时（小时）',
  `required_materials` text COMMENT '所需物料清单（JSON格式）',
  `maintenance_content` text COMMENT '维护内容说明',
  `status` enum('启用','停用') DEFAULT '启用' COMMENT '模板状态',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_asset_type` (`asset_type`),
  KEY `idx_brand` (`brand`),
  KEY `idx_status` (`status`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `maintenance_templates_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=94 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='维护计划模板表';

CREATE TABLE IF NOT EXISTS `maintenance_workorders` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT '1',
  `work_order_no` varchar(50) NOT NULL COMMENT '工单编号',
  `asset_code` varchar(50) DEFAULT NULL COMMENT '关联资产编号',
  `title` varchar(200) NOT NULL COMMENT '工单标题',
  `description` text COMMENT '工单描述',
  `priority` int DEFAULT '3' COMMENT '优先级：1-紧急，2-高，3-中，4-低',
  `status` varchar(20) DEFAULT 'pending' COMMENT '状态',
  `planned_start_date` datetime DEFAULT NULL COMMENT '计划开始时间',
  `planned_end_date` datetime DEFAULT NULL COMMENT '计划结束时间',
  `estimated_hours` decimal(10,2) DEFAULT NULL COMMENT '预估工时',
  `actual_start_date` datetime DEFAULT NULL COMMENT '实际开始时间',
  `actual_end_date` datetime DEFAULT NULL COMMENT '实际结束时间',
  `actual_hours` decimal(10,2) DEFAULT NULL COMMENT '实际工时',
  `assigned_to` varchar(50) DEFAULT NULL COMMENT '负责人',
  `assigned_by` varchar(50) DEFAULT NULL COMMENT '分配人',
  `assigned_at` datetime DEFAULT NULL COMMENT '分配时间',
  `completed_by` varchar(50) DEFAULT NULL COMMENT '完成人',
  `completed_at` datetime DEFAULT NULL COMMENT '完成时间',
  `work_content` text COMMENT '实际工作内容',
  `materials` text COMMENT '材料清单',
  `labor_cost` decimal(12,2) DEFAULT '0.00' COMMENT '人工费',
  `outsourcing_cost` decimal(12,2) DEFAULT '0.00' COMMENT '外包费',
  `other_cost` decimal(12,2) DEFAULT '0.00' COMMENT '其他费用',
  `cancel_reason` text COMMENT '取消原因',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_work_order_no` (`work_order_no`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_status` (`status`),
  KEY `idx_priority` (`priority`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='维护工单表';

CREATE TABLE IF NOT EXISTS `materials` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `material_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `material_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `specification` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `unit` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `subcategory` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `supplier` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `manufacturer` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `min_stock` int DEFAULT '0',
  `max_stock` int DEFAULT '1000',
  `unit_price` decimal(10,2) DEFAULT '0.00',
  `currency` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'CNY',
  `lead_time_days` int DEFAULT '7',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `status` enum('正常','停用','缺货') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '正常',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_material_code_tenant` (`tenant_id`,`material_code`),
  KEY `idx_material_code` (`material_code`),
  KEY `idx_material_name` (`material_name`),
  KEY `idx_category` (`category`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_materials_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `menu_definitions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `menu_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '菜单键（如：/dashboard）',
  `menu_label` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '菜单名称（如：仪表盘）',
  `parent_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '父菜单键（如果是子菜单）',
  `icon` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '图标名称',
  `order_index` int DEFAULT '0' COMMENT '排序索引',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否启用',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `menu_key` (`menu_key`),
  KEY `idx_parent_key` (`parent_key`),
  KEY `idx_order_index` (`order_index`)
) ENGINE=InnoDB AUTO_INCREMENT=2090 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='菜单定义表';

CREATE TABLE IF NOT EXISTS `metrology_attachments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `metrology_id` int NOT NULL COMMENT '计量记录ID',
  `file_name` varchar(255) NOT NULL COMMENT '文件名',
  `file_path` varchar(500) NOT NULL COMMENT '文件路径',
  `file_size` int DEFAULT NULL COMMENT '文件大小（字节）',
  `file_type` varchar(50) DEFAULT NULL COMMENT '文件类型',
  `upload_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_metrology_id` (`metrology_id`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `metrology_attachments_ibfk_1` FOREIGN KEY (`metrology_id`) REFERENCES `metrology_records` (`id`) ON DELETE CASCADE,
  CONSTRAINT `metrology_attachments_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='计量附件表';

CREATE TABLE IF NOT EXISTS `metrology_devices` (
  `id` int NOT NULL AUTO_INCREMENT,
  `device_code` varchar(50) NOT NULL COMMENT '设备编码',
  `device_name` varchar(200) NOT NULL COMMENT '设备名称',
  `device_type` varchar(100) NOT NULL COMMENT '设备类型',
  `asset_id` int DEFAULT NULL COMMENT '关联资产ID',
  `measurement_range` varchar(100) DEFAULT NULL COMMENT '测量范围',
  `accuracy_class` varchar(50) DEFAULT NULL COMMENT '精度等级',
  `manufacturer` varchar(100) DEFAULT NULL COMMENT '制造商',
  `serial_number` varchar(100) DEFAULT NULL COMMENT '序列号',
  `verification_cycle` int DEFAULT '12' COMMENT '检定周期(月)',
  `last_verification_date` date DEFAULT NULL COMMENT '上次检定日期',
  `next_verification_date` date DEFAULT NULL COMMENT '下次检定日期',
  `status` enum('normal','expired','pending','disabled') DEFAULT 'normal' COMMENT '状态',
  `certificate_number` varchar(100) DEFAULT NULL COMMENT '证书编号',
  `tenant_id` int DEFAULT '1' COMMENT '租户ID',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_device_code` (`device_code`),
  KEY `idx_asset_id` (`asset_id`),
  KEY `idx_next_verification` (`next_verification_date`),
  KEY `idx_status` (`status`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='计量器具表';

CREATE TABLE IF NOT EXISTS `metrology_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `record_no` varchar(100) NOT NULL COMMENT '计量单号',
  `asset_code` varchar(100) DEFAULT NULL COMMENT '资产编号',
  `asset_name` varchar(200) DEFAULT NULL COMMENT '资产名称',
  `customer_name` varchar(200) DEFAULT NULL COMMENT '客户名称',
  `specification` varchar(200) DEFAULT NULL COMMENT '规格/型号',
  `serial_number` varchar(100) DEFAULT NULL COMMENT '编号',
  `technical_document` varchar(255) DEFAULT NULL COMMENT '依据技术文件',
  `conformance_standard` varchar(255) DEFAULT NULL COMMENT '符合标准',
  `metrology_type` enum('首次检定','周期检定','校准','期间核查','其他') NOT NULL COMMENT '计量类型',
  `metrology_date` date NOT NULL COMMENT '计量日期',
  `next_metrology_date` date DEFAULT NULL COMMENT '下次计量日期',
  `metrology_agency` varchar(200) DEFAULT NULL COMMENT '计量机构',
  `certificate_no` varchar(100) DEFAULT NULL COMMENT '证书编号',
  `result` enum('合格','不合格','限用','待检') DEFAULT '待检' COMMENT '计量结果',
  `accuracy_level` varchar(50) DEFAULT NULL COMMENT '准确度等级',
  `measurement_range` varchar(100) DEFAULT NULL COMMENT '测量范围',
  `calibration_environment` varchar(255) DEFAULT NULL COMMENT '校准环境',
  `standard_instrument` varchar(255) DEFAULT NULL COMMENT '标准器具',
  `standard_certificate_no` varchar(100) DEFAULT NULL COMMENT '标准证书编号',
  `standard_validity` date DEFAULT NULL COMMENT '标准有效期',
  `uncertainty` varchar(50) DEFAULT NULL COMMENT '扩展不确定度',
  `cost` decimal(10,2) DEFAULT '0.00' COMMENT '计量费用',
  `operator` varchar(50) DEFAULT NULL COMMENT '操作人',
  `approver` varchar(50) DEFAULT NULL COMMENT '批准人',
  `remark` text COMMENT '备注',
  `status` enum('待检','进行中','已完成','已取消') DEFAULT '待检' COMMENT '状态',
  `metrology_cycle` int DEFAULT NULL COMMENT '计量周期（月）',
  `warning_days` int DEFAULT '30' COMMENT '预警天数',
  `certificate_validity_date` date DEFAULT NULL COMMENT '证书有效期',
  `calibration_items` text COMMENT '校准项目',
  `calibration_data` text COMMENT '校准数据',
  `calibration_conclusion` text COMMENT '校准结论',
  `temp20` text COMMENT '预留字段20',
  `temp19` text COMMENT '预留字段19',
  `temp18` text COMMENT '预留字段18',
  `temp17` text COMMENT '预留字段17',
  `temp16` text COMMENT '预留字段16',
  `temp15` text COMMENT '预留字段15',
  `temp14` text COMMENT '预留字段14',
  `temp13` text COMMENT '预留字段13',
  `temp12` text COMMENT '预留字段12',
  `temp11` text COMMENT '预留字段11',
  `temp10` text COMMENT '预留字段10',
  `temp9` text COMMENT '预留字段9',
  `temp8` text COMMENT '预留字段8',
  `temp7` text COMMENT '预留字段7',
  `temp6` text COMMENT '预留字段6',
  `temp5` text COMMENT '预留字段5',
  `temp4` text COMMENT '预留字段4',
  `temp3` text COMMENT '预留字段3',
  `temp2` text COMMENT '预留字段2',
  `temp1` text COMMENT '预留字段1',
  `is_auto_remind` tinyint(1) DEFAULT '1' COMMENT '是否自动提醒',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已删除(0:否,1:是)',
  `deleted_at` datetime DEFAULT NULL COMMENT '删除时间',
  `deleted_by` varchar(64) DEFAULT NULL COMMENT '删除人ID',
  PRIMARY KEY (`id`),
  UNIQUE KEY `record_no` (`record_no`),
  KEY `idx_record_no` (`record_no`),
  KEY `idx_metrology_date` (`metrology_date`),
  KEY `idx_next_metrology_date` (`next_metrology_date`),
  KEY `idx_status` (`status`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_customer_name` (`customer_name`(191)),
  KEY `idx_specification` (`specification`(191)),
  KEY `idx_serial_number` (`serial_number`),
  KEY `idx_technical_document` (`technical_document`(191)),
  KEY `idx_conformance_standard` (`conformance_standard`(191)),
  KEY `idx_metrology_records_is_deleted` (`is_deleted`),
  KEY `idx_next_date` (`next_metrology_date`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='计量管理表';

CREATE TABLE IF NOT EXISTS `module_config_versions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `module_id` varchar(50) NOT NULL COMMENT '模块ID',
  `version` varchar(20) NOT NULL COMMENT '版本号',
  `config` text NOT NULL COMMENT '配置内容',
  `change_log` text COMMENT '变更日志',
  `created_by` varchar(100) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `is_current` tinyint(1) DEFAULT '0' COMMENT '是否当前版本',
  PRIMARY KEY (`id`),
  KEY `idx_tenant_module` (`tenant_id`,`module_id`),
  KEY `idx_version` (`version`),
  KEY `idx_created_at` (`created_at`),
  KEY `module_id` (`module_id`),
  CONSTRAINT `module_config_versions_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE,
  CONSTRAINT `module_config_versions_ibfk_2` FOREIGN KEY (`module_id`) REFERENCES `system_modules` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='模块配置版本表';

CREATE TABLE IF NOT EXISTS `module_dependencies` (
  `id` int NOT NULL AUTO_INCREMENT,
  `module_id` varchar(50) NOT NULL COMMENT '模块ID',
  `dependency_module_id` varchar(50) NOT NULL COMMENT '依赖模块ID',
  `dependency_type` varchar(20) NOT NULL COMMENT '依赖类型',
  `min_version` varchar(20) DEFAULT NULL COMMENT '最低版本',
  `max_version` varchar(20) DEFAULT NULL COMMENT '最高版本',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_module_dependency` (`module_id`,`dependency_module_id`),
  KEY `idx_module_id` (`module_id`),
  KEY `idx_dependency_module_id` (`dependency_module_id`),
  CONSTRAINT `module_dependencies_ibfk_1` FOREIGN KEY (`module_id`) REFERENCES `system_modules` (`id`) ON DELETE CASCADE,
  CONSTRAINT `module_dependencies_ibfk_2` FOREIGN KEY (`dependency_module_id`) REFERENCES `system_modules` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=71 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='模块依赖关系表';

CREATE TABLE IF NOT EXISTS `module_operation_logs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `module_id` varchar(50) NOT NULL COMMENT '模块ID',
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `operation` varchar(50) NOT NULL COMMENT '操作类型',
  `operator` varchar(100) DEFAULT NULL COMMENT '操作人',
  `operation_data` text COMMENT '操作数据',
  `result` varchar(20) DEFAULT NULL COMMENT '操作结果',
  `error_message` text COMMENT '错误信息',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_module_id` (`module_id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_operation` (`operation`),
  KEY `idx_created_at` (`created_at`),
  CONSTRAINT `module_operation_logs_ibfk_1` FOREIGN KEY (`module_id`) REFERENCES `system_modules` (`id`) ON DELETE CASCADE,
  CONSTRAINT `module_operation_logs_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=321 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='模块操作日志表';

CREATE TABLE IF NOT EXISTS `module_runtime_status` (
  `id` int NOT NULL AUTO_INCREMENT,
  `module_id` varchar(50) NOT NULL COMMENT '模块ID',
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `status` varchar(20) NOT NULL COMMENT '运行状态',
  `health_status` varchar(20) DEFAULT NULL COMMENT '健康状态',
  `last_heartbeat` timestamp NULL DEFAULT NULL COMMENT '最后心跳时间',
  `error_message` text COMMENT '错误信息',
  `metrics` text COMMENT '运行指标',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_module_tenant` (`module_id`,`tenant_id`),
  KEY `idx_module_id` (`module_id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_status` (`status`),
  KEY `idx_health_status` (`health_status`),
  CONSTRAINT `module_runtime_status_ibfk_1` FOREIGN KEY (`module_id`) REFERENCES `system_modules` (`id`) ON DELETE CASCADE,
  CONSTRAINT `module_runtime_status_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='模块运行状态表';

CREATE TABLE IF NOT EXISTS `operation_logs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `asset_id` int NOT NULL COMMENT '资产ID',
  `operation_type` enum('start','stop','maintenance','fault') NOT NULL COMMENT '操作类型',
  `operation_time` datetime NOT NULL COMMENT '操作时间',
  `operator_id` int DEFAULT NULL COMMENT '操作人ID',
  `start_time` datetime DEFAULT NULL COMMENT '开机时间',
  `end_time` datetime DEFAULT NULL COMMENT '关机时间',
  `duration_minutes` int DEFAULT NULL COMMENT '运行时长(分钟)',
  `notes` text COMMENT '备注',
  `tenant_id` int DEFAULT '1' COMMENT '租户ID',
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_asset_id` (`asset_id`),
  KEY `idx_operation_time` (`operation_time`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='设备运行记录表';

CREATE TABLE IF NOT EXISTS `permission_audit_logs` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL COMMENT '操作用户ID',
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `action` varchar(50) NOT NULL COMMENT '操作类型: grant/deny/revoke/change_scope',
  `target_type` varchar(20) NOT NULL COMMENT '目标类型: role/user',
  `target_id` varchar(100) NOT NULL COMMENT '目标ID',
  `permission` varchar(100) DEFAULT NULL COMMENT '权限代码',
  `old_value` text COMMENT '旧值',
  `new_value` text COMMENT '新值',
  `ip_address` varchar(45) DEFAULT NULL COMMENT 'IP地址',
  `user_agent` text COMMENT 'User Agent',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_target` (`target_type`,`target_id`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='权限变更审计日志表';

CREATE TABLE IF NOT EXISTS `permission_definitions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `permission` varchar(100) NOT NULL,
  `category` varchar(50) NOT NULL COMMENT '权限分类',
  `name` varchar(200) NOT NULL COMMENT '权限名称',
  `description` varchar(500) DEFAULT NULL COMMENT '权限描述',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `permission` (`permission`),
  KEY `idx_category` (`category`)
) ENGINE=InnoDB AUTO_INCREMENT=52 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='权限定义表';

CREATE TABLE IF NOT EXISTS `preventive_maintenance_plans` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `template_id` int DEFAULT NULL COMMENT '模板ID',
  `asset_code` varchar(100) NOT NULL COMMENT '资产编号',
  `asset_name` varchar(200) NOT NULL COMMENT '资产名称',
  `plan_name` varchar(200) NOT NULL COMMENT '计划名称',
  `maintenance_type` varchar(50) NOT NULL COMMENT '维护类型',
  `cycle_type` enum('按天','按周','按月','按季度','按年') NOT NULL COMMENT '周期类型',
  `trigger_type` enum('time','usage','condition') DEFAULT 'time' COMMENT '触发类型：time-时间, usage-使用量, condition-条件',
  `current_usage` decimal(15,2) DEFAULT '0.00' COMMENT '当前使用量（运行小时数或使用次数）',
  `usage_threshold` decimal(15,2) DEFAULT NULL COMMENT '使用量阈值',
  `cycle_value` int NOT NULL COMMENT '周期值',
  `next_maintenance_date` date NOT NULL COMMENT '下次维护日期',
  `maintenance_content` text COMMENT '维护内容',
  `maintenance_items` text COMMENT '维护项目清单（JSON格式）',
  `required_materials` text COMMENT '所需物料清单（JSON格式）',
  `estimated_hours` decimal(10,2) DEFAULT NULL COMMENT '预计工时（小时）',
  `auto_generate_workorder` tinyint(1) DEFAULT '1' COMMENT '是否自动生成工单',
  `responsible_person` varchar(50) DEFAULT NULL COMMENT '负责人',
  `status` enum('启用','停用','已完成') DEFAULT '启用' COMMENT '计划状态',
  `last_maintenance_date` date DEFAULT NULL COMMENT '上次维护日期',
  `remark` text COMMENT '备注',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  `usage_type` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_next_maintenance_date` (`next_maintenance_date`),
  KEY `idx_status` (`status`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `fk_preventive_maintenance_plans_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `preventive_maintenance_plans_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='预防性维护计划表';

CREATE TABLE IF NOT EXISTS `procurement_files` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `request_id` int NOT NULL,
  `file_type` varchar(32) NOT NULL,
  `file_name` varchar(255) NOT NULL,
  `file_path` varchar(500) NOT NULL,
  `mime_type` varchar(120) DEFAULT NULL,
  `file_size` bigint DEFAULT '0',
  `uploaded_by` int DEFAULT NULL,
  `uploaded_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_request_id` (`request_id`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `procurement_requests` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `request_no` varchar(64) NOT NULL,
  `title` varchar(255) NOT NULL,
  `department` varchar(128) DEFAULT NULL,
  `applicant` varchar(128) DEFAULT NULL,
  `budget` decimal(14,2) DEFAULT '0.00',
  `status` varchar(32) NOT NULL DEFAULT 'draft',
  `approval_by` varchar(128) DEFAULT NULL,
  `approval_opinion` text,
  `approval_at` datetime DEFAULT NULL,
  `execution_by` varchar(128) DEFAULT NULL,
  `execution_result` text,
  `execution_at` datetime DEFAULT NULL,
  `acceptance_record_id` int DEFAULT NULL,
  `remark` text,
  `created_by` int DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_request_no_tenant` (`tenant_id`,`request_no`),
  KEY `idx_tenant_status` (`tenant_id`,`status`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `public_page_views` (
  `page_key` varchar(100) NOT NULL,
  `view_count` bigint unsigned NOT NULL DEFAULT '0',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`page_key`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `quality_control` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `record_no` varchar(100) NOT NULL COMMENT '质控单号',
  `asset_code` varchar(100) DEFAULT NULL COMMENT '资产编号',
  `asset_name` varchar(200) DEFAULT NULL COMMENT '资产名称',
  `qc_type` enum('日常质控','定期质控','专项质控','验收质控','其他') NOT NULL COMMENT '质控类型',
  `qc_date` date NOT NULL COMMENT '质控日期',
  `next_qc_date` date DEFAULT NULL COMMENT '下次质控日期',
  `qc_item` varchar(200) DEFAULT NULL COMMENT '质控项目',
  `qc_method` varchar(200) DEFAULT NULL COMMENT '质控方法',
  `qc_person` varchar(50) DEFAULT NULL COMMENT '质控人员',
  `department` varchar(100) DEFAULT NULL COMMENT '科室',
  `qc_standard` varchar(200) DEFAULT NULL COMMENT '质控标准',
  `result` enum('合格','不合格','待检','整改中') DEFAULT '待检' COMMENT '质控结果',
  `qc_value` varchar(100) DEFAULT NULL COMMENT '质控数值',
  `standard_value` varchar(100) DEFAULT NULL COMMENT '标准值',
  `actual_value` varchar(100) DEFAULT NULL COMMENT '实际值',
  `tolerance` varchar(100) DEFAULT NULL COMMENT '允差',
  `deviation` varchar(100) DEFAULT NULL COMMENT '偏差',
  `operator` varchar(50) DEFAULT NULL COMMENT '操作人',
  `reviewer` varchar(50) DEFAULT NULL COMMENT '审核人',
  `review_date` date DEFAULT NULL COMMENT '审核日期',
  `remark` text COMMENT '备注',
  `status` enum('待检','进行中','已完成','已取消','整改中') DEFAULT '待检' COMMENT '状态',
  `qc_cycle` int DEFAULT NULL COMMENT '质控周期（月）',
  `warning_days` int DEFAULT '30' COMMENT '预警天数',
  `is_auto_remind` tinyint(1) DEFAULT '1' COMMENT '是否自动提醒',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `record_no` (`record_no`),
  KEY `idx_record_no` (`record_no`),
  KEY `idx_qc_date` (`qc_date`),
  KEY `idx_next_qc_date` (`next_qc_date`),
  KEY `idx_status` (`status`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_qc_tenant_asset_status` (`tenant_id`,`asset_code`,`status`),
  KEY `idx_qc_tenant_qc_date` (`tenant_id`,`qc_date`),
  KEY `idx_qc_tenant_type_result` (`tenant_id`,`qc_type`,`result`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='质控管理表';

CREATE TABLE IF NOT EXISTS `quality_control_attachments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `qc_id` int NOT NULL COMMENT '质控记录ID',
  `file_name` varchar(255) NOT NULL COMMENT '文件名',
  `file_path` varchar(500) NOT NULL COMMENT '文件路径',
  `file_size` int DEFAULT NULL COMMENT '文件大小（字节）',
  `file_type` varchar(50) DEFAULT NULL COMMENT '文件类型',
  `upload_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_qc_id` (`qc_id`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `quality_control_attachments_ibfk_1` FOREIGN KEY (`qc_id`) REFERENCES `quality_control_records` (`id`) ON DELETE CASCADE,
  CONSTRAINT `quality_control_attachments_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='质控附件表';

CREATE TABLE IF NOT EXISTS `quality_control_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `record_no` varchar(100) NOT NULL COMMENT '质控单号',
  `asset_code` varchar(100) DEFAULT NULL COMMENT '资产编号',
  `asset_name` varchar(200) DEFAULT NULL COMMENT '资产名称',
  `qc_type` enum('日常质控','定期质控','专项质控','验收质控','其他') NOT NULL COMMENT '质控类型',
  `qc_date` date NOT NULL COMMENT '质控日期',
  `next_qc_date` date DEFAULT NULL COMMENT '下次质控日期',
  `qc_item` varchar(200) DEFAULT NULL COMMENT '质控项目',
  `qc_method` varchar(200) DEFAULT NULL COMMENT '质控方法',
  `qc_person` varchar(50) DEFAULT NULL COMMENT '质控人员',
  `department` varchar(100) DEFAULT NULL COMMENT '科室',
  `qc_standard` varchar(200) DEFAULT NULL COMMENT '质控标准',
  `result` enum('合格','不合格','待检','整改中') DEFAULT '待检' COMMENT '质控结果',
  `qc_value` varchar(100) DEFAULT NULL COMMENT '质控数值',
  `standard_value` varchar(100) DEFAULT NULL COMMENT '标准值',
  `actual_value` varchar(100) DEFAULT NULL COMMENT '实际值',
  `tolerance` varchar(100) DEFAULT NULL COMMENT '允差',
  `deviation` varchar(100) DEFAULT NULL COMMENT '偏差',
  `operator` varchar(50) DEFAULT NULL COMMENT '操作人',
  `reviewer` varchar(50) DEFAULT NULL COMMENT '审核人',
  `review_date` date DEFAULT NULL COMMENT '审核日期',
  `remark` text COMMENT '备注',
  `status` enum('待检','进行中','已完成','已取消','整改中') DEFAULT '待检' COMMENT '状态',
  `qc_cycle` int DEFAULT NULL COMMENT '质控周期（月）',
  `warning_days` int DEFAULT '30' COMMENT '预警天数',
  `is_auto_remind` tinyint(1) DEFAULT '1' COMMENT '是否自动提醒',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已删除(0:否,1:是)',
  `deleted_at` datetime DEFAULT NULL COMMENT '删除时间',
  `deleted_by` varchar(64) DEFAULT NULL COMMENT '删除人ID',
  PRIMARY KEY (`id`),
  UNIQUE KEY `record_no` (`record_no`),
  KEY `idx_record_no` (`record_no`),
  KEY `idx_qc_date` (`qc_date`),
  KEY `idx_next_qc_date` (`next_qc_date`),
  KEY `idx_status` (`status`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_qc_tenant_asset_status` (`tenant_id`,`asset_code`,`status`),
  KEY `idx_qc_tenant_qc_date` (`tenant_id`,`qc_date`),
  KEY `idx_qc_tenant_type_result` (`tenant_id`,`qc_type`,`result`),
  KEY `idx_quality_control_records_is_deleted` (`is_deleted`),
  KEY `idx_next_date` (`next_qc_date`),
  CONSTRAINT `quality_control_records_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='质控管理表';

CREATE TABLE IF NOT EXISTS `quality_control_reports` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL,
  `report_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `start_date` date DEFAULT NULL,
  `end_date` date DEFAULT NULL,
  `format` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'json',
  `report_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_quality_control_reports_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='质控报告存档表';

CREATE TABLE IF NOT EXISTS `quality_management_alerts` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `alert_type` enum('metrology','quality_control') NOT NULL COMMENT '预警类型',
  `record_id` int NOT NULL COMMENT '记录ID',
  `asset_code` varchar(100) DEFAULT NULL COMMENT '资产编号',
  `asset_name` varchar(200) DEFAULT NULL COMMENT '资产名称',
  `alert_date` date NOT NULL COMMENT '预警日期',
  `due_date` date NOT NULL COMMENT '到期日期',
  `days_remaining` int DEFAULT NULL COMMENT '剩余天数',
  `alert_level` enum('normal','warning','urgent') DEFAULT 'normal' COMMENT '预警级别',
  `is_read` tinyint(1) DEFAULT '0' COMMENT '是否已读',
  `is_handled` tinyint(1) DEFAULT '0' COMMENT '是否已处理',
  `handled_by` varchar(50) DEFAULT NULL COMMENT '处理人',
  `handled_at` datetime DEFAULT NULL COMMENT '处理时间',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_alert_type` (`alert_type`),
  KEY `idx_record_id` (`record_id`),
  KEY `idx_alert_date` (`alert_date`),
  KEY `idx_due_date` (`due_date`),
  KEY `idx_is_read` (`is_read`),
  KEY `idx_is_handled` (`is_handled`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `quality_management_alerts_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='质量管理预警记录表';

CREATE TABLE IF NOT EXISTS `quality_management_cycles` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT NULL COMMENT '租户ID',
  `asset_code` varchar(100) DEFAULT NULL COMMENT '资产编号',
  `asset_name` varchar(200) DEFAULT NULL COMMENT '资产名称',
  `metrology_cycle` int DEFAULT NULL COMMENT '计量周期（月）',
  `metrology_warning_days` int DEFAULT '30' COMMENT '计量预警天数',
  `quality_control_cycle` int DEFAULT NULL COMMENT '质控周期（月）',
  `quality_control_warning_days` int DEFAULT '30' COMMENT '质控预警天数',
  `is_auto_remind` tinyint(1) DEFAULT '1' COMMENT '是否自动提醒',
  `remark` text COMMENT '备注',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `quality_management_cycles_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='质量管理周期配置表';

CREATE TABLE IF NOT EXISTS `resource_permissions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `resource_type` varchar(50) NOT NULL COMMENT '资源类型: asset/device/maintenance等',
  `resource_action` varchar(50) NOT NULL COMMENT '资源操作: create/read/update/delete/approve',
  `permission_code` varchar(100) NOT NULL COMMENT '权限代码',
  `permission_name` varchar(200) NOT NULL COMMENT '权限名称',
  `description` varchar(500) DEFAULT NULL COMMENT '描述',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否启用',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_resource_action` (`resource_type`,`resource_action`),
  KEY `idx_resource_type` (`resource_type`)
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资源权限定义表';

CREATE TABLE IF NOT EXISTS `risk_alert_state` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `asset_code` varchar(100) NOT NULL,
  `ema_score` decimal(10,2) NOT NULL DEFAULT '0.00',
  `last_raw_score` decimal(10,2) NOT NULL DEFAULT '0.00',
  `last_alert_level` varchar(20) NOT NULL DEFAULT 'low',
  `last_alert_at` datetime DEFAULT NULL,
  `cooldown_until` datetime DEFAULT NULL,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_risk_alert_state_tenant_asset` (`tenant_id`,`asset_code`),
  KEY `idx_risk_alert_state_tenant_level` (`tenant_id`,`last_alert_level`),
  KEY `idx_risk_alert_state_cooldown` (`cooldown_until`)
) ENGINE=InnoDB AUTO_INCREMENT=251 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `risk_assessments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `asset_id` int NOT NULL COMMENT '资产ID',
  `risk_level` enum('low','medium','high','critical') NOT NULL COMMENT '风险等级',
  `risk_score` int DEFAULT NULL COMMENT '风险评分',
  `assessment_date` date NOT NULL COMMENT '评估日期',
  `next_assessment_date` date DEFAULT NULL COMMENT '下次评估日期',
  `assessor_id` int DEFAULT NULL COMMENT '评估人ID',
  `risk_factors` text COMMENT '风险因素',
  `mitigation_measures` text COMMENT '缓解措施',
  `status` enum('active','mitigated','closed') DEFAULT 'active' COMMENT '状态',
  `tenant_id` int DEFAULT '1' COMMENT '租户ID',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_asset_id` (`asset_id`),
  KEY `idx_risk_level` (`risk_level`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='风险评估表';

CREATE TABLE IF NOT EXISTS `risk_controls` (
  `id` int NOT NULL AUTO_INCREMENT,
  `assessment_id` int NOT NULL COMMENT '评估ID',
  `control_measure` text NOT NULL COMMENT '控制措施',
  `responsible_person_id` int DEFAULT NULL COMMENT '负责人ID',
  `due_date` date DEFAULT NULL COMMENT '截止日期',
  `completion_date` date DEFAULT NULL COMMENT '完成日期',
  `status` enum('pending','in_progress','completed') DEFAULT 'pending' COMMENT '状态',
  `effectiveness_rating` enum('excellent','good','fair','poor') DEFAULT NULL COMMENT '效果评级',
  `tenant_id` int DEFAULT '1' COMMENT '租户ID',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_assessment_id` (`assessment_id`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='风险控制措施表';

CREATE TABLE IF NOT EXISTS `risk_score_snapshots` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `asset_code` varchar(100) NOT NULL,
  `market_risk` decimal(10,2) NOT NULL DEFAULT '0.00',
  `compliance_risk` decimal(10,2) NOT NULL DEFAULT '0.00',
  `device_risk` decimal(10,2) NOT NULL DEFAULT '0.00',
  `raw_score` decimal(10,2) NOT NULL DEFAULT '0.00',
  `smoothed_score` decimal(10,2) NOT NULL DEFAULT '0.00',
  `alert_level` varchar(20) NOT NULL DEFAULT 'low',
  `fatigue_suppressed` tinyint(1) NOT NULL DEFAULT '0',
  `suppress_reason` varchar(100) DEFAULT NULL,
  `confidence` decimal(6,4) NOT NULL DEFAULT '0.0000',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_risk_score_snapshots_tenant_asset_time` (`tenant_id`,`asset_code`,`created_at`),
  KEY `idx_risk_score_snapshots_tenant_level` (`tenant_id`,`alert_level`,`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=351 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `role_data_scopes` (
  `id` int NOT NULL AUTO_INCREMENT,
  `role` varchar(50) NOT NULL COMMENT '角色代码',
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `data_scope` varchar(20) NOT NULL DEFAULT 'own' COMMENT '数据范围: all/department/own/custom',
  `custom_department_codes` text COMMENT '自定义科室代码列表，逗号分隔',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_role_tenant` (`role`,`tenant_id`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='角色数据范围配置表';

CREATE TABLE IF NOT EXISTS `role_hierarchy` (
  `id` int NOT NULL AUTO_INCREMENT,
  `role` varchar(50) NOT NULL COMMENT '子角色代码',
  `parent_role` varchar(50) NOT NULL COMMENT '父角色代码',
  `inherit_permissions` tinyint(1) DEFAULT '1' COMMENT '是否继承权限',
  `inherit_menus` tinyint(1) DEFAULT '1' COMMENT '是否继承菜单',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_role_parent` (`role`,`parent_role`),
  KEY `idx_parent_role` (`parent_role`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='角色层级表';

CREATE TABLE IF NOT EXISTS `role_menu_permissions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `role` varchar(50) NOT NULL COMMENT '角色代码',
  `menu_key` varchar(100) NOT NULL COMMENT '菜单键',
  `is_visible` tinyint(1) DEFAULT '1' COMMENT '是否可见（1=可见，0=不可见）',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_role_menu` (`role`,`menu_key`),
  KEY `idx_role` (`role`),
  KEY `idx_menu_key` (`menu_key`)
) ENGINE=InnoDB AUTO_INCREMENT=34558 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='角色菜单权限表';

CREATE TABLE IF NOT EXISTS `role_permissions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `role` varchar(50) NOT NULL,
  `permission` varchar(100) NOT NULL,
  `description` varchar(500) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_role_permission` (`role`,`permission`)
) ENGINE=InnoDB AUTO_INCREMENT=149 DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `roles` (
  `id` int NOT NULL AUTO_INCREMENT,
  `role_code` varchar(50) NOT NULL COMMENT '角色代码（如：system_admin）',
  `role_name` varchar(100) NOT NULL COMMENT '角色名称（如：系统管理员）',
  `description` text COMMENT '角色描述',
  `is_system_role` tinyint(1) DEFAULT '0' COMMENT '是否系统内置角色（1=是，0=否，系统角色不能删除）',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否启用（1=启用，0=禁用）',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  PRIMARY KEY (`id`),
  UNIQUE KEY `role_code` (`role_code`),
  KEY `idx_role_code` (`role_code`),
  KEY `idx_is_active` (`is_active`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='角色表';

CREATE TABLE IF NOT EXISTS `rsa` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `private_key` text NOT NULL,
  `public_key` text NOT NULL,
  `salt` text NOT NULL,
  `create_time` bigint NOT NULL,
  `update_time` bigint NOT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_rsa_id` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `safety_inspections` (
  `id` int NOT NULL AUTO_INCREMENT,
  `inspection_code` varchar(50) NOT NULL COMMENT '检测编号',
  `inspection_name` varchar(200) NOT NULL COMMENT '检测名称',
  `asset_id` int DEFAULT NULL COMMENT '关联资产ID',
  `inspection_type` enum('electrical','radiation','mechanical','chemical','biological','other') NOT NULL,
  `inspection_date` date NOT NULL COMMENT '检测日期',
  `inspection_org` varchar(200) DEFAULT NULL COMMENT '检测机构',
  `inspection_result` enum('pass','fail','conditional') NOT NULL COMMENT '检测结果',
  `next_inspection_date` date DEFAULT NULL COMMENT '下次检测日期',
  `status` enum('completed','pending_rectification','overdue') DEFAULT 'completed',
  `tenant_id` int DEFAULT '1',
  `created_by` int DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_asset_id` (`asset_id`),
  KEY `idx_inspection_date` (`inspection_date`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='安全检测表';

CREATE TABLE IF NOT EXISTS `scan_logs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `asset_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `scan_type` enum('verify','inventory','other') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `scan_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `scan_time` datetime NOT NULL,
  `tenant_id` int NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_scan_time` (`scan_time`),
  KEY `idx_scan_type` (`scan_type`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_scan_logs_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `sentences` (
  `id` int NOT NULL AUTO_INCREMENT,
  `sentence` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `sms_verification_codes` (
  `id` int NOT NULL AUTO_INCREMENT,
  `phone` varchar(20) NOT NULL COMMENT '手机号',
  `code` varchar(10) NOT NULL COMMENT '验证码',
  `tenant_id` int DEFAULT NULL COMMENT '租户ID（新用户注册时为NULL）',
  `expires_at` datetime NOT NULL COMMENT '过期时间',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_phone` (`phone`),
  KEY `idx_expires` (`expires_at`)
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='短信验证码表';

CREATE TABLE IF NOT EXISTS `special_equipment` (
  `id` int NOT NULL AUTO_INCREMENT,
  `equipment_code` varchar(50) NOT NULL COMMENT '设备编码',
  `equipment_name` varchar(200) NOT NULL COMMENT '设备名称',
  `equipment_type` enum('pressure_vessel','elevator','crane','forklift','boiler','other') NOT NULL,
  `asset_id` int DEFAULT NULL COMMENT '关联资产ID',
  `registration_code` varchar(100) DEFAULT NULL COMMENT '使用登记证编号',
  `install_location` varchar(200) DEFAULT NULL COMMENT '安装地点',
  `next_inspection_date` date DEFAULT NULL COMMENT '下次检验日期',
  `safety_status` enum('normal','expiring','expired','stopped') DEFAULT 'normal',
  `status` enum('in_use','out_of_service','scrapped') DEFAULT 'in_use',
  `tenant_id` int DEFAULT '1',
  `created_by` int DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_next_inspection` (`next_inspection_date`),
  KEY `idx_safety_status` (`safety_status`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='特种设备表';

CREATE TABLE IF NOT EXISTS `special_equipment_inspections` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int DEFAULT '1',
  `inspection_code` varchar(50) DEFAULT NULL,
  `equipment_id` int DEFAULT NULL,
  `inspection_type` varchar(50) NOT NULL DEFAULT 'regular',
  `inspection_date` date DEFAULT NULL,
  `inspection_result` varchar(50) DEFAULT NULL,
  `inspection_org` varchar(200) DEFAULT NULL,
  `inspection_agency` varchar(200) DEFAULT NULL,
  `inspector` varchar(100) DEFAULT NULL,
  `inspection_items` text,
  `inspection_content` text,
  `issues_found` text,
  `rectification_measures` text,
  `rectification_deadline` date DEFAULT NULL,
  `certificate_no` varchar(100) DEFAULT NULL,
  `certificate_image` varchar(500) DEFAULT NULL,
  `next_date` date DEFAULT NULL,
  `next_inspection_date` date DEFAULT NULL,
  `remarks` text,
  `remark` text,
  `created_by` int DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_sei_tenant` (`tenant_id`),
  KEY `idx_sei_equipment` (`equipment_id`),
  KEY `idx_sei_inspection_date` (`inspection_date`),
  KEY `idx_sei_next_inspection_date` (`next_inspection_date`),
  KEY `idx_sei_next_date` (`next_date`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

CREATE TABLE IF NOT EXISTS `staff_qualifications` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL COMMENT '用户ID',
  `qualification_type` varchar(100) NOT NULL COMMENT '资质类型',
  `qualification_code` varchar(50) DEFAULT NULL COMMENT '资质编号',
  `qualification_name` varchar(200) NOT NULL COMMENT '资质名称',
  `qualification_level` varchar(50) DEFAULT NULL COMMENT '资质等级',
  `certificate_no` varchar(100) DEFAULT NULL COMMENT '证书编号',
  `issue_date` date NOT NULL COMMENT '颁发日期',
  `expiry_date` date DEFAULT NULL COMMENT '到期日期',
  `professional_field` varchar(100) DEFAULT NULL COMMENT '专业领域',
  `applicable_equipment` text COMMENT '适用设备范围',
  `certificate_image` varchar(500) DEFAULT NULL COMMENT '证书图片',
  `scope` text COMMENT '资质适用范围',
  `issuing_authority` varchar(200) DEFAULT NULL COMMENT '颁发机构',
  `attachments` json DEFAULT NULL COMMENT '附件列表',
  `status` enum('active','expired','revoked') DEFAULT 'active' COMMENT '状态',
  `remarks` text COMMENT '备注',
  `tenant_id` int DEFAULT '1' COMMENT '租户ID',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_tenant_qualification_code` (`tenant_id`,`qualification_code`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_expiry_date` (`expiry_date`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='人员资质表';

CREATE TABLE IF NOT EXISTS `super_users` (
  `id` int NOT NULL AUTO_INCREMENT,
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `password` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `real_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('active','inactive') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'active',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `last_login_at` datetime DEFAULT NULL,
  `login_count` int DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `sys_arg` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `pkey` varchar(255) NOT NULL COMMENT 'pkey',
  `pval` varchar(255) DEFAULT NULL COMMENT 'pval',
  `ptype` varchar(255) NOT NULL DEFAULT 'str' COMMENT 'str or file',
  `sort_no` int NOT NULL DEFAULT '1' COMMENT 'sort_no',
  PRIMARY KEY (`id`),
  KEY `ix_sys_arg_id` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `sys_assistant` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `domain` varchar(255) NOT NULL,
  `type` int NOT NULL,
  `configuration` text,
  `create_time` bigint NOT NULL,
  `description` text,
  `app_id` varchar(255) DEFAULT NULL COMMENT 'app_id',
  `app_secret` varchar(255) DEFAULT NULL COMMENT 'app_secret',
  PRIMARY KEY (`id`),
  KEY `ix_sys_assistant_id` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `sys_user` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `account` varchar(255) NOT NULL,
  `name` varchar(255) NOT NULL,
  `password` varchar(255) NOT NULL,
  `email` varchar(255) DEFAULT NULL,
  `oid` bigint NOT NULL,
  `status` int NOT NULL,
  `create_time` bigint NOT NULL,
  `language` varchar(255) NOT NULL DEFAULT 'zh-CN',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `sys_user_ws` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `uid` bigint NOT NULL,
  `oid` bigint NOT NULL,
  `weight` int NOT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_sys_user_ws_id` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `sys_workspace` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `create_time` bigint NOT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_sys_workspace_id` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `system_module_menus` (
  `id` int NOT NULL AUTO_INCREMENT,
  `module_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '模块ID',
  `menu_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '菜单键',
  `is_enabled` tinyint(1) DEFAULT '1' COMMENT '是否启用',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_module_menu` (`module_id`,`menu_key`),
  KEY `idx_module_id` (`module_id`),
  KEY `idx_menu_key` (`menu_key`)
) ENGINE=InnoDB AUTO_INCREMENT=973 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='系统模块菜单映射表';

CREATE TABLE IF NOT EXISTS `system_modules` (
  `id` varchar(50) NOT NULL COMMENT '模块ID',
  `name` varchar(100) NOT NULL COMMENT '模块名称',
  `version` varchar(20) NOT NULL COMMENT '模块版本',
  `description` text COMMENT '模块描述',
  `category` varchar(50) NOT NULL COMMENT '模块分类',
  `type` varchar(20) NOT NULL COMMENT '模块类型',
  `status` varchar(20) NOT NULL DEFAULT 'stable' COMMENT '模块状态',
  `author` varchar(100) DEFAULT NULL COMMENT '作者',
  `dependencies` text COMMENT '依赖关系',
  `compatibility` text COMMENT '兼容性规则',
  `frontend_config` text COMMENT '前端配置',
  `backend_config` text COMMENT '后端配置',
  `config_schema` text COMMENT '配置项定义',
  `default_config` text COMMENT '默认配置',
  `interfaces` text COMMENT '接口定义',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_category` (`category`),
  KEY `idx_status` (`status`),
  KEY `idx_type` (`type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='系统模块元数据表';

CREATE TABLE IF NOT EXISTS `technical_document_asset_relations` (
  `id` int NOT NULL AUTO_INCREMENT,
  `document_id` int NOT NULL COMMENT '技术资料ID',
  `asset_code` varchar(255) DEFAULT NULL COMMENT '资产编码',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `tenant_id` int NOT NULL DEFAULT '0' COMMENT '租户ID',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_document_asset_code` (`document_id`,`asset_code`(100)),
  KEY `idx_asset_code` (`asset_code`(100)),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `technical_document_asset_relations_ibfk_1` FOREIGN KEY (`document_id`) REFERENCES `technical_documents` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='技术资料与资产关联表';

CREATE TABLE IF NOT EXISTS `technical_document_categories` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `category_code` varchar(50) NOT NULL COMMENT '分类代码',
  `category_name` varchar(100) NOT NULL COMMENT '分类名称',
  `parent_id` int DEFAULT '0' COMMENT '父分类ID',
  `description` text COMMENT '分类描述',
  `icon` varchar(50) DEFAULT NULL COMMENT '分类图标',
  `sort_order` int DEFAULT '0' COMMENT '排序',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否启用',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_tenant_code` (`tenant_id`,`category_code`),
  KEY `idx_parent_id` (`parent_id`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资料分类表';

CREATE TABLE IF NOT EXISTS `technical_document_comments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `document_id` int NOT NULL COMMENT '资料ID',
  `user_id` int NOT NULL COMMENT '用户ID',
  `user_name` varchar(100) DEFAULT NULL COMMENT '用户姓名',
  `content` text NOT NULL COMMENT '评论内容',
  `parent_id` int DEFAULT '0' COMMENT '父评论ID',
  `is_resolved` tinyint(1) DEFAULT '0' COMMENT '是否已解决',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `tenant_id` int NOT NULL DEFAULT '0' COMMENT '租户ID',
  PRIMARY KEY (`id`),
  KEY `idx_document_id` (`document_id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_parent_id` (`parent_id`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资料评论表';

CREATE TABLE IF NOT EXISTS `technical_document_downloads` (
  `id` int NOT NULL AUTO_INCREMENT,
  `document_id` int NOT NULL COMMENT '资料ID',
  `downloaded_by` varchar(50) DEFAULT NULL COMMENT '下载人',
  `download_date` datetime DEFAULT NULL COMMENT '下载日期',
  `download_ip` varchar(50) DEFAULT NULL COMMENT '下载IP地址',
  `user_agent` text COMMENT '用户代理',
  `tenant_id` int NOT NULL DEFAULT '0' COMMENT '租户ID',
  PRIMARY KEY (`id`),
  KEY `idx_document` (`document_id`),
  KEY `idx_download_date` (`download_date`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `technical_document_downloads_ibfk_1` FOREIGN KEY (`document_id`) REFERENCES `technical_documents` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=37 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='技术资料下载记录表';

CREATE TABLE IF NOT EXISTS `technical_document_favorites` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL COMMENT '用户ID',
  `document_id` int NOT NULL COMMENT '资料ID',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `tenant_id` int NOT NULL DEFAULT '0' COMMENT '租户ID',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_user_doc` (`user_id`,`document_id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_document_id` (`document_id`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资料收藏表';

CREATE TABLE IF NOT EXISTS `technical_document_history` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL COMMENT '用户ID',
  `document_id` int NOT NULL COMMENT '资料ID',
  `action_type` varchar(20) NOT NULL COMMENT '操作类型: view/download/share/edit',
  `ip_address` varchar(45) DEFAULT NULL COMMENT 'IP地址',
  `user_agent` text COMMENT 'User Agent',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `tenant_id` int NOT NULL DEFAULT '0' COMMENT '租户ID',
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_document_id` (`document_id`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资料访问历史表';

CREATE TABLE IF NOT EXISTS `technical_document_reminders` (
  `id` int NOT NULL AUTO_INCREMENT,
  `document_id` int NOT NULL COMMENT '资料ID',
  `user_id` int NOT NULL COMMENT '提醒用户ID',
  `reminder_type` varchar(20) NOT NULL COMMENT '提醒类型: expiry/update_review',
  `reminder_date` datetime NOT NULL COMMENT '提醒日期',
  `message` text COMMENT '提醒消息',
  `is_sent` tinyint(1) DEFAULT '0' COMMENT '是否已发送',
  `sent_at` datetime DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_document_id` (`document_id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_reminder_date` (`reminder_date`),
  KEY `idx_is_sent` (`is_sent`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资料提醒表';

CREATE TABLE IF NOT EXISTS `technical_document_shares` (
  `id` int NOT NULL AUTO_INCREMENT,
  `document_id` int NOT NULL COMMENT '资料ID',
  `share_token` varchar(100) NOT NULL COMMENT '分享令牌',
  `share_url` varchar(500) DEFAULT NULL COMMENT '分享URL',
  `expires_at` datetime DEFAULT NULL COMMENT '过期时间',
  `max_uploads` int DEFAULT '1' COMMENT '最大上传次数（用于外部上传）',
  `current_uploads` int DEFAULT '0' COMMENT '当前上传次数',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_at` datetime DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否激活',
  `remark` text COMMENT '备注',
  `tenant_id` int NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `share_token` (`share_token`),
  KEY `idx_document` (`document_id`),
  KEY `idx_share_token` (`share_token`),
  KEY `idx_expires_at` (`expires_at`),
  KEY `idx_tenant_id` (`tenant_id`),
  CONSTRAINT `fk_technical_document_shares_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `technical_document_shares_ibfk_1` FOREIGN KEY (`document_id`) REFERENCES `technical_documents` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='技术资料分享链接表';

CREATE TABLE IF NOT EXISTS `technical_document_stats` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `stat_date` date NOT NULL COMMENT '统计日期',
  `total_documents` int DEFAULT '0' COMMENT '资料总数',
  `total_downloads` int DEFAULT '0' COMMENT '下载次数',
  `total_views` int DEFAULT '0' COMMENT '浏览次数',
  `total_shares` int DEFAULT '0' COMMENT '分享次数',
  `storage_used` bigint DEFAULT '0' COMMENT '存储使用量(bytes)',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_tenant_date` (`tenant_id`,`stat_date`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_stat_date` (`stat_date`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资料统计表';

CREATE TABLE IF NOT EXISTS `technical_document_tag_relations` (
  `id` int NOT NULL AUTO_INCREMENT,
  `document_id` int NOT NULL COMMENT '资料ID',
  `tag_id` int NOT NULL COMMENT '标签ID',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `tenant_id` int NOT NULL DEFAULT '0' COMMENT '租户ID',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_doc_tag` (`document_id`,`tag_id`),
  KEY `idx_document_id` (`document_id`),
  KEY `idx_tag_id` (`tag_id`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资料标签关联表';

CREATE TABLE IF NOT EXISTS `technical_document_tags` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `tag_name` varchar(50) NOT NULL COMMENT '标签名称',
  `tag_color` varchar(20) DEFAULT '#1890ff' COMMENT '标签颜色',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_tenant_tag` (`tenant_id`,`tag_name`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资料标签表';

CREATE TABLE IF NOT EXISTS `technical_document_templates` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `template_name` varchar(100) NOT NULL COMMENT '模板名称',
  `template_description` text COMMENT '模板描述',
  `category_id` int DEFAULT NULL COMMENT '默认分类ID',
  `template_fields` text COMMENT '模板字段配置',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否启用',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_category_id` (`category_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资料模板表';

CREATE TABLE IF NOT EXISTS `technical_document_versions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `document_id` int NOT NULL COMMENT '资料ID',
  `version_number` varchar(20) NOT NULL COMMENT '版本号',
  `file_path` varchar(500) NOT NULL COMMENT '文件路径',
  `file_size` bigint DEFAULT '0' COMMENT '文件大小',
  `file_hash` varchar(64) DEFAULT NULL COMMENT '文件哈希',
  `change_log` text COMMENT '版本变更说明',
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `created_by_id` int DEFAULT NULL COMMENT '创建人ID',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_document_id` (`document_id`),
  KEY `idx_version` (`document_id`,`version_number`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资料版本表';

CREATE TABLE IF NOT EXISTS `technical_documents` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `title` varchar(255) NOT NULL COMMENT '资料标题',
  `description` text COMMENT '资料描述',
  `file_name` varchar(255) NOT NULL COMMENT '文件名',
  `file_path` varchar(1000) NOT NULL COMMENT '文件路径',
  `file_type` varchar(100) DEFAULT NULL COMMENT '文件类型（MIME类型）',
  `file_size` bigint DEFAULT NULL COMMENT '文件大小（字节）',
  `category` varchar(100) DEFAULT NULL COMMENT '资料分类（如：使用手册、维修手册、技术规范等）',
  `asset_type` varchar(100) DEFAULT NULL COMMENT '关联资产类型',
  `brand` varchar(100) DEFAULT NULL COMMENT '关联品牌',
  `model` varchar(200) DEFAULT NULL COMMENT '关联型号',
  `version` varchar(50) DEFAULT NULL COMMENT '版本号',
  `language` varchar(50) DEFAULT 'zh-CN' COMMENT '语言',
  `upload_source` enum('内部上传','外部上传') DEFAULT '内部上传' COMMENT '上传来源',
  `upload_token` varchar(100) DEFAULT NULL COMMENT '外部上传令牌（用于分享链接）',
  `token_expires_at` datetime DEFAULT NULL COMMENT '令牌过期时间',
  `uploaded_by` varchar(50) DEFAULT NULL COMMENT '上传人',
  `upload_date` datetime DEFAULT NULL COMMENT '上传日期',
  `download_count` int DEFAULT '0' COMMENT '下载次数',
  `view_count` int DEFAULT '0' COMMENT '查看次数',
  `is_public` tinyint(1) DEFAULT '0' COMMENT '是否公开（1=公开，0=仅内部）',
  `status` enum('active','archived','deleted') DEFAULT 'active' COMMENT '状态',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `review_status` enum('pending','approved','rejected') DEFAULT 'pending' COMMENT '审核状态（pending=待审核，approved=已通过，rejected=已拒绝）',
  `reviewed_by` varchar(50) DEFAULT NULL COMMENT '审核人',
  `reviewed_at` datetime DEFAULT NULL COMMENT '审核时间',
  `review_comment` text COMMENT '审核意见',
  PRIMARY KEY (`id`),
  KEY `idx_category` (`category`),
  KEY `idx_asset_type` (`asset_type`),
  KEY `idx_brand` (`brand`),
  KEY `idx_upload_token` (`upload_token`),
  KEY `idx_status` (`status`),
  KEY `idx_upload_date` (`upload_date`),
  KEY `idx_review_status` (`review_status`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_tech_docs_tenant_category` (`tenant_id`,`category`),
  KEY `idx_tech_docs_tenant_upload_date` (`tenant_id`,`upload_date`,`created_at`),
  CONSTRAINT `fk_technical_documents_tenant` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `technical_documents_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='技术资料表';

CREATE TABLE IF NOT EXISTS `temp_assets` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `asset_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `asset_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `brand` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `model` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `specification` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `department` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('在用','闲置','维修','报废') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '闲置',
  `source` enum('盘盈','临时') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT '临时',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `created_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_asset_name` (`asset_name`(191)),
  KEY `idx_status` (`status`),
  KEY `idx_source` (`source`),
  KEY `idx_created_at` (`created_at`),
  CONSTRAINT `temp_assets_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `tenant_module_config_logs` (
  `id` varchar(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `tenant_id` varchar(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `tenant_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `module_id` varchar(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `module_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `action` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `old_value` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `new_value` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `operator_id` varchar(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `operator_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_module_id` (`module_id`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `tenant_module_configs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `module_id` varchar(50) NOT NULL COMMENT '模块ID',
  `enabled` tinyint(1) DEFAULT '0' COMMENT '是否启用',
  `config` text COMMENT '模块配置',
  `version` varchar(20) DEFAULT NULL COMMENT '配置版本',
  `enabled_at` timestamp NULL DEFAULT NULL COMMENT '启用时间',
  `disabled_at` timestamp NULL DEFAULT NULL COMMENT '禁用时间',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_tenant_module` (`tenant_id`,`module_id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_module_id` (`module_id`),
  KEY `idx_enabled` (`enabled`),
  CONSTRAINT `tenant_module_configs_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE,
  CONSTRAINT `tenant_module_configs_ibfk_2` FOREIGN KEY (`module_id`) REFERENCES `system_modules` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=928 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='租户模块配置表';

CREATE TABLE IF NOT EXISTS `tenant_module_menus` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `module_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `menu_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_enabled` tinyint(1) DEFAULT '1',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_tenant_module_menu` (`tenant_id`,`module_id`,`menu_key`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_module_id` (`module_id`),
  KEY `idx_menu_key` (`menu_key`)
) ENGINE=InnoDB AUTO_INCREMENT=49831 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='租户模块菜单关联表';

CREATE TABLE IF NOT EXISTS `tenants` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_code` varchar(50) NOT NULL COMMENT '租户编码',
  `tenant_name` varchar(200) NOT NULL COMMENT '企业名称',
  `contact_person` varchar(50) DEFAULT NULL COMMENT '联系人',
  `contact_phone` varchar(50) DEFAULT NULL COMMENT '联系电话',
  `contact_email` varchar(100) DEFAULT NULL COMMENT '联系邮箱',
  `address` text COMMENT '企业地址',
  `license_no` varchar(100) DEFAULT NULL COMMENT '营业执照号',
  `status` enum('active','inactive','suspended') DEFAULT 'active' COMMENT '状态',
  `max_users` int DEFAULT '100' COMMENT '最大用户数',
  `max_assets` int DEFAULT '10000' COMMENT '最大资产数',
  `subscription_type` enum('free','basic','professional','enterprise') DEFAULT 'free' COMMENT '订阅类型',
  `subscription_start_date` date DEFAULT NULL COMMENT '订阅开始日期',
  `subscription_end_date` date DEFAULT NULL COMMENT '订阅结束日期',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  `invitation_code` varchar(50) DEFAULT NULL COMMENT '邀请码',
  PRIMARY KEY (`id`),
  UNIQUE KEY `tenant_code` (`tenant_code`),
  KEY `idx_tenant_code` (`tenant_code`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=22 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='租户（企业）表';

CREATE TABLE IF NOT EXISTS `terms` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `term` varchar(255) NOT NULL,
  `definition` varchar(255) NOT NULL,
  `domain` varchar(255) NOT NULL,
  `create_time` int NOT NULL,
  PRIMARY KEY (`id`),
  KEY `ix_terms_id` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `time_access_controls` (
  `id` int NOT NULL AUTO_INCREMENT,
  `role` varchar(50) NOT NULL COMMENT '角色代码',
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `allowed_hours` varchar(100) NOT NULL COMMENT '允许访问的小时，格式: 9-18',
  `allowed_days` varchar(100) NOT NULL COMMENT '允许访问的星期，格式: 1,2,3,4,5',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '是否启用',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_role_tenant_time` (`role`,`tenant_id`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='时间访问控制表';

CREATE TABLE IF NOT EXISTS `training_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL COMMENT '用户ID',
  `training_name` varchar(200) NOT NULL COMMENT '培训名称',
  `training_type` varchar(100) DEFAULT NULL COMMENT '培训类型',
  `training_date` date NOT NULL COMMENT '培训日期',
  `duration_hours` int DEFAULT NULL COMMENT '培训时长(小时)',
  `training_provider` varchar(200) DEFAULT NULL COMMENT '培训机构',
  `trainer` varchar(100) DEFAULT NULL COMMENT '培训师',
  `certificate_number` varchar(100) DEFAULT NULL COMMENT '证书编号',
  `attachment_url` varchar(500) DEFAULT NULL COMMENT '附件',
  `tenant_id` int DEFAULT '1' COMMENT '租户ID',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_training_date` (`training_date`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='培训记录表';

CREATE TABLE IF NOT EXISTS `transfer_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `transfer_no` varchar(100) NOT NULL COMMENT '调配单号',
  `asset_code` varchar(255) NOT NULL COMMENT '资产ID',
  `from_department` varchar(100) NOT NULL COMMENT '调出部门',
  `to_department` varchar(100) NOT NULL COMMENT '调入部门',
  `from_location` varchar(200) DEFAULT NULL COMMENT '调出位置',
  `to_location` varchar(200) DEFAULT NULL COMMENT '调入位置',
  `from_person` varchar(50) DEFAULT NULL COMMENT '调出责任人',
  `to_person` varchar(50) DEFAULT NULL COMMENT '调入责任人',
  `transfer_date` date NOT NULL COMMENT '调配日期',
  `transfer_reason` text COMMENT '调配原因',
  `status` enum('待审批','已批准','已完成','已取消') DEFAULT '待审批' COMMENT '调配状态',
  `approver` varchar(50) DEFAULT NULL COMMENT '审批人',
  `approve_date` date DEFAULT NULL COMMENT '审批日期',
  `remark` text COMMENT '备注',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  `created_by` varchar(50) DEFAULT NULL COMMENT '创建人',
  `tenant_id` varchar(255) DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `idx_asset` (`asset_code`(191)),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='资产调配表';

CREATE TABLE IF NOT EXISTS `uptime_statistics` (
  `id` int NOT NULL AUTO_INCREMENT,
  `asset_id` int NOT NULL COMMENT '资产ID',
  `device_type` enum('life_support','large_equipment','regular_equipment') NOT NULL COMMENT '设备类型',
  `statistics_date` date NOT NULL COMMENT '统计日期',
  `planned_hours` int NOT NULL COMMENT '计划运行小时数',
  `actual_hours` int NOT NULL COMMENT '实际运行小时数',
  `downtime_hours` int DEFAULT '0' COMMENT '停机小时数',
  `uptime_rate` decimal(5,2) DEFAULT NULL COMMENT '开机率(%)',
  `downtime_reason` text COMMENT '停机原因',
  `tenant_id` int DEFAULT '1' COMMENT '租户ID',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_asset_id` (`asset_id`),
  KEY `idx_statistics_date` (`statistics_date`),
  KEY `idx_device_type` (`device_type`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='开机率统计表';

CREATE TABLE IF NOT EXISTS `usage_triggered_maintenance` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL,
  `asset_code` varchar(100) NOT NULL,
  `asset_name` varchar(200) DEFAULT NULL,
  `plan_id` int DEFAULT NULL,
  `work_order_id` int DEFAULT NULL,
  `trigger_date` date NOT NULL,
  `current_usage` decimal(15,2) NOT NULL,
  `threshold_usage` decimal(15,2) NOT NULL,
  `usage_type` varchar(50) NOT NULL,
  `status` enum('pending','processed','canceled') DEFAULT 'pending',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_plan_id` (`plan_id`),
  KEY `idx_work_order_id` (`work_order_id`),
  KEY `idx_status` (`status`),
  KEY `idx_usage_triggered_maintenance_tenant_id` (`tenant_id`),
  CONSTRAINT `usage_triggered_maintenance_ibfk_1` FOREIGN KEY (`plan_id`) REFERENCES `preventive_maintenance_plans` (`id`) ON DELETE SET NULL,
  CONSTRAINT `usage_triggered_maintenance_ibfk_2` FOREIGN KEY (`work_order_id`) REFERENCES `work_orders` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='使用量触发维护表';

CREATE TABLE IF NOT EXISTS `user_data_scopes` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL COMMENT '用户ID',
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `data_scope` varchar(20) NOT NULL DEFAULT 'own' COMMENT '数据范围: all/department/own/custom',
  `custom_department_codes` text COMMENT '自定义科室代码列表，逗号分隔',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_user_tenant` (`user_id`,`tenant_id`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='用户数据范围配置表';

CREATE TABLE IF NOT EXISTS `user_desktop_preferences` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `tenant_id` int NOT NULL,
  `hidden_modules` json DEFAULT NULL,
  `icon_layout` json DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_user_tenant` (`user_id`,`tenant_id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='用户桌面显示偏好';

CREATE TABLE IF NOT EXISTS `user_managed_departments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `tenant_id` int NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT '2000-01-01 00:00:00',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `department_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_user_department` (`user_id`,`tenant_id`,`department_code`),
  KEY `tenant_id` (`tenant_id`),
  KEY `idx_user_managed_departments_user_tenant` (`user_id`,`tenant_id`),
  CONSTRAINT `user_managed_departments_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `user_managed_departments_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=42 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `user_menu_permissions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL COMMENT '用户ID',
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `menu_key` varchar(100) NOT NULL COMMENT '菜单键',
  `is_visible` tinyint(1) DEFAULT '1' COMMENT '是否可见',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_user_menu` (`user_id`,`tenant_id`,`menu_key`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='用户菜单权限表';

CREATE TABLE IF NOT EXISTS `user_permission_denies` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL COMMENT '用户ID',
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `permission` varchar(100) NOT NULL COMMENT '被拒绝的权限代码',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_user_deny` (`user_id`,`tenant_id`,`permission`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='用户权限拒绝表';

CREATE TABLE IF NOT EXISTS `user_permissions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL COMMENT '用户ID',
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `permission` varchar(100) NOT NULL COMMENT '权限代码',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_user_permission` (`user_id`,`tenant_id`,`permission`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='用户权限表';

CREATE TABLE IF NOT EXISTS `user_tenant_roles` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int NOT NULL,
  `tenant_id` int NOT NULL,
  `role` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `managed_departments` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `is_default` tinyint(1) DEFAULT '0',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `status` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_user_tenant` (`user_id`,`tenant_id`),
  KEY `idx_user_tenant_roles_tenant_id` (`tenant_id`),
  KEY `idx_user_tenant_roles_user_id` (`user_id`),
  KEY `idx_user_tenant_roles_user_tenant` (`user_id`,`tenant_id`),
  CONSTRAINT `user_tenant_roles_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `user_tenant_roles_ibfk_2` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=146 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `users` (
  `id` int NOT NULL AUTO_INCREMENT,
  `username` varchar(50) NOT NULL,
  `password` varchar(100) NOT NULL,
  `real_name` varchar(50) NOT NULL,
  `department_code` varchar(50) DEFAULT NULL,
  `email` varchar(100) DEFAULT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `status` enum('active','inactive') DEFAULT 'active',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  `updated_by` varchar(100) DEFAULT NULL,
  `tenant_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_users_username` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=219 DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `work_order_history` (
  `id` int NOT NULL AUTO_INCREMENT,
  `work_order_id` int NOT NULL,
  `action_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `action_description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `action_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `action_at` datetime NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_work_order_id` (`work_order_id`),
  KEY `idx_action_at` (`action_at`),
  KEY `idx_created_at` (`created_at`),
  CONSTRAINT `work_order_history_ibfk_1` FOREIGN KEY (`work_order_id`) REFERENCES `work_orders` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `work_order_materials` (
  `id` int NOT NULL AUTO_INCREMENT,
  `work_order_id` int NOT NULL,
  `material_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `specification` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `quantity` decimal(10,2) NOT NULL,
  `unit` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `unit_price` decimal(10,2) DEFAULT NULL,
  `total_cost` decimal(15,2) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_work_order_id` (`work_order_id`),
  CONSTRAINT `work_order_materials_ibfk_1` FOREIGN KEY (`work_order_id`) REFERENCES `work_orders` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `work_orders` (
  `id` int NOT NULL AUTO_INCREMENT,
  `work_order_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `tenant_id` int NOT NULL,
  `asset_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `asset_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `maintenance_plan_id` int DEFAULT NULL,
  `source_type` enum('fault','preventive','inspection','other') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `priority` enum('low','normal','high','urgent') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'normal',
  `status` enum('pending','assigned','in_progress','pending_acceptance','completed','closed','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `assigned_to` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `assigned_at` datetime DEFAULT NULL,
  `started_at` datetime DEFAULT NULL,
  `completed_at` datetime DEFAULT NULL,
  `accepted_at` datetime DEFAULT NULL,
  `accepted_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `estimated_hours` decimal(10,2) DEFAULT NULL,
  `actual_hours` decimal(10,2) DEFAULT NULL,
  `fault_cause` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `solution` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `acceptance_result` enum('passed','failed','partial') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `satisfaction_score` int DEFAULT NULL,
  `created_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `work_order_no` (`work_order_no`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_status` (`status`),
  KEY `idx_priority` (`priority`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `workflow_connections` (
  `id` varchar(36) NOT NULL,
  `workflow_id` varchar(36) NOT NULL COMMENT '工作流ID',
  `source_node_id` varchar(100) NOT NULL COMMENT '源节点ID',
  `source_output` varchar(50) NOT NULL COMMENT '源输出端',
  `target_node_id` varchar(100) NOT NULL COMMENT '目标节点ID',
  `target_input` varchar(50) NOT NULL COMMENT '目标输入端',
  `conn_condition` text COMMENT '连接条件',
  `metadata` text COMMENT '元数据',
  PRIMARY KEY (`id`),
  KEY `idx_workflow_id` (`workflow_id`),
  KEY `idx_source_node` (`source_node_id`),
  KEY `idx_target_node` (`target_node_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COMMENT='工作流连接表';

CREATE TABLE IF NOT EXISTS `workflow_definitions` (
  `id` varchar(64) NOT NULL,
  `name` varchar(255) NOT NULL,
  `description` text,
  `category` varchar(64) DEFAULT NULL,
  `definition` text,
  `version` int DEFAULT '1',
  `is_active` tinyint(1) DEFAULT '1',
  `tenant_id` varchar(64) DEFAULT NULL,
  `created_by` varchar(64) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_is_active` (`is_active`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `workflow_execution_logs` (
  `id` varchar(36) NOT NULL,
  `execution_id` varchar(36) NOT NULL COMMENT '执行ID',
  `workflow_id` varchar(36) NOT NULL COMMENT '工作流ID',
  `node_id` varchar(100) NOT NULL COMMENT '节点ID',
  `node_name` varchar(200) NOT NULL COMMENT '节点名称',
  `node_type` varchar(100) NOT NULL COMMENT '节点类型',
  `status` enum('pending','running','completed','failed','skipped') DEFAULT 'pending' COMMENT '状态',
  `started_at` datetime DEFAULT NULL COMMENT '开始时间',
  `finished_at` datetime DEFAULT NULL COMMENT '完成时间',
  `duration_ms` int DEFAULT NULL COMMENT '耗时',
  `input_data` text COMMENT '输入数据',
  `output_data` text COMMENT '输出数据',
  `error_message` text COMMENT '错误信息',
  `error_stack` text COMMENT '错误堆栈',
  `retry_count` int DEFAULT '0' COMMENT '重试次数',
  `metadata` text COMMENT '元数据',
  PRIMARY KEY (`id`),
  KEY `idx_execution_id` (`execution_id`),
  KEY `idx_workflow_id` (`workflow_id`),
  KEY `idx_node_id` (`node_id`),
  KEY `idx_started_at` (`started_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COMMENT='执行日志表';

CREATE TABLE IF NOT EXISTS `workflow_executions` (
  `id` varchar(64) NOT NULL,
  `workflow_id` varchar(64) NOT NULL,
  `status` enum('pending','running','completed','failed','cancelled') DEFAULT 'pending',
  `trigger_data` text,
  `node_states` text,
  `started_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `completed_at` datetime DEFAULT NULL,
  `error_message` text,
  `tenant_id` varchar(64) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_workflow_id` (`workflow_id`),
  KEY `idx_status` (`status`),
  KEY `idx_started_at` (`started_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `workflow_logs` (
  `id` varchar(64) NOT NULL,
  `execution_id` varchar(64) NOT NULL,
  `node_id` varchar(64) DEFAULT NULL,
  `level` enum('info','warn','error','debug') DEFAULT 'info',
  `message` text,
  `data` text,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_execution_id` (`execution_id`),
  KEY `idx_node_id` (`node_id`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;

CREATE TABLE IF NOT EXISTS `workflow_nodes` (
  `id` varchar(36) NOT NULL,
  `workflow_id` varchar(36) NOT NULL COMMENT '工作流ID',
  `node_id` varchar(100) NOT NULL COMMENT '节点标识',
  `name` varchar(200) NOT NULL COMMENT '节点名称',
  `type` varchar(100) NOT NULL COMMENT '节点类型',
  `category` varchar(50) DEFAULT 'action' COMMENT '节点分类',
  `position` text NOT NULL COMMENT '位置坐标 {x, y}',
  `parameters` text COMMENT '节点参数',
  `input_config` text COMMENT '输入配置',
  `output_config` text COMMENT '输出配置',
  `conditions` text COMMENT '条件配置',
  `error_handler` text COMMENT '错误处理',
  `metadata` text COMMENT '元数据',
  PRIMARY KEY (`id`),
  KEY `idx_workflow_id` (`workflow_id`),
  KEY `idx_node_id` (`node_id`),
  KEY `idx_type` (`type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COMMENT='工作流节点表';

CREATE TABLE IF NOT EXISTS `workflows` (
  `id` varchar(36) NOT NULL,
  `tenant_id` varchar(36) NOT NULL COMMENT '租户ID',
  `name` varchar(200) NOT NULL COMMENT '工作流名称',
  `description` text COMMENT '工作流描述',
  `category` varchar(100) DEFAULT 'general' COMMENT '分类',
  `version` varchar(20) DEFAULT '1.0' COMMENT '版本号',
  `status` enum('draft','active','inactive','archived') DEFAULT 'draft' COMMENT '状态',
  `definition` text NOT NULL COMMENT '工作流定义(JSON)',
  `settings` text COMMENT '执行设置',
  `triggers` text COMMENT '触发器配置',
  `tags` text COMMENT '标签',
  `metadata` text COMMENT '元数据',
  `created_by` varchar(36) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_by` varchar(36) DEFAULT NULL COMMENT '更新人',
  `updated_at` datetime DEFAULT NULL,
  `deleted_at` datetime DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT '0' COMMENT '是否激活: 0-未激活, 1-已激活',
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_status` (`status`),
  KEY `idx_category` (`category`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COMMENT='工作流定义表';

-- =====================================================
-- 维保管理模块表
-- =====================================================

CREATE TABLE IF NOT EXISTS `warranty_contracts` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `contract_no` varchar(100) NOT NULL COMMENT '合同编号',
  `contract_name` varchar(200) NOT NULL COMMENT '合同名称',
  `asset_code` varchar(100) NOT NULL COMMENT '资产编号',
  `asset_name` varchar(200) DEFAULT NULL COMMENT '资产名称',
  `supplier_name` varchar(200) DEFAULT NULL COMMENT '供应商/服务商名称',
  `supplier_contact` varchar(200) DEFAULT NULL COMMENT '供应商联系方式',
  `warranty_type` enum('原厂保修','延保','第三方保修','自行维修') DEFAULT '原厂保修' COMMENT '保修类型',
  `start_date` date NOT NULL COMMENT '保修开始日期',
  `end_date` date NOT NULL COMMENT '保修结束日期',
  `contract_amount` decimal(12,2) DEFAULT 0.00 COMMENT '合同金额',
  `coverage_scope` text COMMENT '保修范围',
  `service_level` varchar(200) DEFAULT NULL COMMENT '服务等级/响应级别',
  `response_time` varchar(100) DEFAULT NULL COMMENT '响应时间承诺',
  `status` enum('生效中','即将到期','已过期','已终止') DEFAULT '生效中' COMMENT '合同状态',
  `remark` text COMMENT '备注',
  `created_by` varchar(100) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_contract_no_tenant` (`contract_no`, `tenant_id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_status` (`status`),
  KEY `idx_end_date` (`end_date`),
  KEY `idx_warranty_contracts_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='保修合同表';

CREATE TABLE IF NOT EXISTS `warranty_invoices` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `contract_id` int DEFAULT NULL COMMENT '关联合同ID',
  `invoice_no` varchar(100) NOT NULL COMMENT '发票编号',
  `invoice_code` varchar(100) DEFAULT NULL COMMENT '发票代码',
  `invoice_type` enum('增值税专用发票','增值税普通发票','其他') DEFAULT '增值税普通发票' COMMENT '发票类型',
  `amount` decimal(12,2) NOT NULL DEFAULT 0.00 COMMENT '发票金额',
  `tax_amount` decimal(12,2) DEFAULT 0.00 COMMENT '税额',
  `invoice_date` date NOT NULL COMMENT '开票日期',
  `issuer` varchar(200) DEFAULT NULL COMMENT '开票方',
  `receiver` varchar(200) DEFAULT NULL COMMENT '收票方',
  `file_path` varchar(500) DEFAULT NULL COMMENT '发票文件路径',
  `status` enum('待审核','已审核','已驳回') DEFAULT '待审核' COMMENT '审核状态',
  `remark` text COMMENT '备注',
  `created_by` varchar(100) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_invoice_no_tenant` (`invoice_no`, `tenant_id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_contract_id` (`contract_id`),
  KEY `idx_invoice_date` (`invoice_date`),
  KEY `idx_warranty_invoices_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='保修发票表';

CREATE TABLE IF NOT EXISTS `warranty_payments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `contract_id` int DEFAULT NULL COMMENT '关联合同ID',
  `invoice_id` int DEFAULT NULL COMMENT '关联发票ID',
  `payment_no` varchar(100) NOT NULL COMMENT '付款单号',
  `payment_type` enum('预付款','进度款','尾款','全款','其他') DEFAULT '全款' COMMENT '付款类型',
  `amount` decimal(12,2) NOT NULL DEFAULT 0.00 COMMENT '付款金额',
  `payment_method` enum('银行转账','支票','现金','其他') DEFAULT '银行转账' COMMENT '付款方式',
  `payment_date` date NOT NULL COMMENT '付款日期',
  `payee` varchar(200) DEFAULT NULL COMMENT '收款方',
  `bank_account` varchar(100) DEFAULT NULL COMMENT '收款账号',
  `status` enum('待付款','已付款','已取消') DEFAULT '待付款' COMMENT '付款状态',
  `file_path` varchar(500) DEFAULT NULL COMMENT '付款凭证文件路径',
  `remark` text COMMENT '备注',
  `created_by` varchar(100) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_payment_no_tenant` (`payment_no`, `tenant_id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_contract_id` (`contract_id`),
  KEY `idx_invoice_id` (`invoice_id`),
  KEY `idx_payment_date` (`payment_date`),
  KEY `idx_warranty_payments_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='保修付款表';

CREATE TABLE IF NOT EXISTS `warranty_archives` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `contract_id` int DEFAULT NULL COMMENT '关联合同ID',
  `archive_no` varchar(100) NOT NULL COMMENT '档案编号',
  `archive_name` varchar(200) NOT NULL COMMENT '档案名称',
  `document_type` enum('合同原件','验收报告','保修证书','技术资料','维修记录','其他') DEFAULT '其他' COMMENT '文档类型',
  `asset_code` varchar(100) DEFAULT NULL COMMENT '关联资产编号',
  `file_path` varchar(500) NOT NULL COMMENT '文件路径',
  `file_size` bigint DEFAULT 0 COMMENT '文件大小(字节)',
  `description` text COMMENT '描述',
  `archive_date` date DEFAULT NULL COMMENT '归档日期',
  `retention_until` date DEFAULT NULL COMMENT '保管截止日期',
  `status` enum('在档','已移交','已销毁') DEFAULT '在档' COMMENT '档案状态',
  `created_by` varchar(100) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_archive_no_tenant` (`archive_no`, `tenant_id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_contract_id` (`contract_id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_document_type` (`document_type`),
  KEY `idx_warranty_archives_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='保修档案表';

CREATE TABLE IF NOT EXISTS `warranty_info` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `asset_code` varchar(100) NOT NULL COMMENT '资产编号',
  `asset_name` varchar(200) DEFAULT NULL COMMENT '资产名称',
  `contract_id` int DEFAULT NULL COMMENT '关联合同ID',
  `warranty_status` enum('在保','过保','即将到期','待确认') DEFAULT '在保' COMMENT '保修状态',
  `warranty_type` enum('原厂保修','延保','第三方保修','自行维修','无保修') DEFAULT '原厂保修' COMMENT '保修类型',
  `start_date` date DEFAULT NULL COMMENT '保修开始日期',
  `end_date` date DEFAULT NULL COMMENT '保修结束日期',
  `warranty_period_months` int DEFAULT NULL COMMENT '保修期（月）',
  `supplier_name` varchar(200) DEFAULT NULL COMMENT '保修服务方',
  `supplier_contact` varchar(200) DEFAULT NULL COMMENT '服务方联系方式',
  `coverage_details` text COMMENT '保修范围详情',
  `exclusions` text COMMENT '不包含项',
  `service_hotline` varchar(100) DEFAULT NULL COMMENT '服务热线',
  `remark` text COMMENT '备注',
  `created_by` varchar(100) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_asset_code_tenant` (`asset_code`, `tenant_id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_contract_id` (`contract_id`),
  KEY `idx_warranty_status` (`warranty_status`),
  KEY `idx_end_date` (`end_date`),
  KEY `idx_warranty_info_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='保修信息维护表';

CREATE TABLE IF NOT EXISTS `warranty_history` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `warranty_info_id` int DEFAULT NULL COMMENT '关联保修信息ID',
  `asset_code` varchar(100) NOT NULL COMMENT '资产编号',
  `asset_name` varchar(200) DEFAULT NULL COMMENT '资产名称',
  `change_type` enum('新增','修改','续保','过保','终止','状态变更') NOT NULL COMMENT '变更类型',
  `field_name` varchar(100) DEFAULT NULL COMMENT '变更字段',
  `old_value` text COMMENT '旧值',
  `new_value` text COMMENT '新值',
  `change_description` text COMMENT '变更说明',
  `changed_by` varchar(100) DEFAULT NULL COMMENT '操作人',
  `changed_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '操作时间',
  PRIMARY KEY (`id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_warranty_info_id` (`warranty_info_id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_change_type` (`change_type`),
  KEY `idx_changed_at` (`changed_at`),
  KEY `idx_warranty_history_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='保修历史记录表';

CREATE TABLE IF NOT EXISTS `warranty_reminders` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `warranty_info_id` int DEFAULT NULL COMMENT '关联保修信息ID',
  `contract_id` int DEFAULT NULL COMMENT '关联合同ID',
  `asset_code` varchar(100) NOT NULL COMMENT '资产编号',
  `asset_name` varchar(200) DEFAULT NULL COMMENT '资产名称',
  `reminder_type` enum('到期提醒','过保提醒','报修提醒','续保提醒') DEFAULT '到期提醒' COMMENT '提醒类型',
  `reminder_date` date NOT NULL COMMENT '提醒日期',
  `expire_date` date DEFAULT NULL COMMENT '到期日期',
  `recipients` text COMMENT '提醒人列表(JSON数组：用户ID或姓名)',
  `recipient_names` text COMMENT '提醒人姓名列表(逗号分隔，便于展示)',
  `reminder_days_before` int DEFAULT 30 COMMENT '提前几天提醒',
  `message` text COMMENT '提醒消息内容',
  `status` enum('待发送','已发送','已处理','已忽略') DEFAULT '待发送' COMMENT '提醒状态',
  `sent_at` timestamp NULL DEFAULT NULL COMMENT '发送时间',
  `created_by` varchar(100) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_warranty_info_id` (`warranty_info_id`),
  KEY `idx_asset_code` (`asset_code`),
  KEY `idx_reminder_date` (`reminder_date`),
  KEY `idx_status` (`status`),
  KEY `idx_warranty_reminders_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='保修提醒表';

CREATE TABLE IF NOT EXISTS `warranty_reminder_configs` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int NOT NULL COMMENT '租户ID',
  `asset_code` varchar(100) DEFAULT NULL COMMENT '资产编号（空表示全局配置）',
  `reminder_days_before` int NOT NULL DEFAULT 30 COMMENT '提前几天提醒',
  `reminder_dates` text COMMENT '提醒日期列表(JSON数组，如每月1号、到期前30天等)',
  `recipients` text COMMENT '提醒人列表(JSON数组)',
  `recipient_names` text COMMENT '提醒人姓名列表(逗号分隔)',
  `reminder_types` varchar(500) DEFAULT '["system"]' COMMENT '提醒方式(JSON)',
  `enabled` tinyint(1) DEFAULT 1 COMMENT '是否启用',
  `created_by` varchar(100) DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_tenant` (`tenant_id`),
  KEY `idx_asset_code` (`asset_code`),
  UNIQUE KEY `uk_tenant_asset` (`tenant_id`, `asset_code`),
  KEY `idx_warranty_reminder_configs_tenant_id` (`tenant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='保修提醒配置表';

SET FOREIGN_KEY_CHECKS=1;
